 35→var mailboxesStatusCmd = &cobra.Command{
 36→	Use:   "status",
 37→	Short: "Show mailbox usage and remaining capacity",
 38→	RunE: func(cmd *cobra.Command, args []string) error {
 39→		d, err := db.Open()
 40→		if err != nil {
 41→			return err
 42→		}
 43→		defer d.Close()
 44→
 45→		mailboxes, err := sequence.ListMailboxes(d, timeNow())
 46→		if err != nil {
 47→			return err
 48→		}
 49→
 50→		if mailboxesFormat == "json" {
 51→			enc := json.NewEncoder(os.Stdout)
 52→			enc.SetIndent("", "  ")
 53→			return enc.Encode(mailboxes)
 54→		}
 55→
 56→		if len(mailboxes) == 0 {
 57→			fmt.Println("  No mailboxes tracked yet. Send an email first to create mailbox state.")
 58→			return nil
 59→		}
 60→
 61→		for _, mailbox := range mailboxes {
 62→			fmt.Printf("  [%s] %s\n", mailbox.Status, mailbox.Email)
 63→			fmt.Printf("    transport: %s | rotation: %s\n", mailbox.TransportEmail, mailbox.RotationGroup)
 64→			fmt.Printf("    warmup: %s | reputation: %d | priority: %d\n", mailbox.WarmupStage, mailbox.ReputationScore, mailbox.Priority)
 65→			fmt.Printf("    send window: %02d:00-%02d:00 %s | min gap: %d min\n", mailbox.SendWindowStartHour, mailbox.SendWindowEndHour, mailbox.SendWindowTimezone, mailbox.MinGapMinutes)
 66→			fmt.Printf("    first touches: %d/%d\n", mailbox.FirstTouchesSent, mailbox.FirstTouchDailyCap)
 67→			fmt.Printf("    follow-ups: %d/%d\n", mailbox.FollowUpsSent, mailbox.FollowUpDailyCap)
 68→			if mailbox.ReplyDailyCap > 0 {
 69→				fmt.Printf("    replies: %d/%d\n", mailbox.RepliesSent, mailbox.ReplyDailyCap)
 70→			} else {
 71→				fmt.Printf("    replies: %d/unlimited\n", mailbox.RepliesSent)
 72→			}
 73→			if mailbox.LastUsedAt != "" {
 74→				fmt.Printf("    last used: %s\n", shortDate(mailbox.LastUsedAt))
 75→			}
 76→			if mailbox.LastBounceAt != "" {
 77→				fmt.Printf("    last bounce: %s\n", shortDate(mailbox.LastBounceAt))
 78→			}
 79→		}
 80→		return nil
 81→	},
 82→}
