 84→var mailboxesHealthCmd = &cobra.Command{
 85→	Use:   "health",
 86→	Short: "Show deliverability health by mailbox",
 87→	RunE: func(cmd *cobra.Command, args []string) error {
 88→		d, err := db.Open()
 89→		if err != nil {
 90→			return err
 91→		}
 92→		defer d.Close()
 93→
 94→		health, err := sequence.ListMailboxHealth(d, timeNow(), mailboxesHealthDNS)
 95→		if err != nil {
 96→			return err
 97→		}
 98→
 99→		if mailboxesFormat == "json" {
100→			enc := json.NewEncoder(os.Stdout)
101→			enc.SetIndent("", "  ")
102→			return enc.Encode(health)
103→		}
104→
105→		if len(health) == 0 {
106→			fmt.Println("  No mailboxes tracked yet. Send an email first to create mailbox state.")
107→			return nil
108→		}
109→
110→		for _, item := range health {
111→			fmt.Printf("  [%s] %s\n", item.Risk, item.Mailbox.Email)
112→			fmt.Printf("    health score: %d | reputation: %d\n", item.HealthScore, item.Mailbox.ReputationScore)
113→			fmt.Printf("    warmup day: %d | caps: first-touch=%d follow-up=%d reply=%d\n", item.WarmupDay, item.EffectiveFirstTouchCap, item.EffectiveFollowUpCap, item.EffectiveReplyCap)
114→			fmt.Printf("    bounce rate (14d): %.1f%% (%d/%d)\n", item.BounceStats.BounceRate*100, item.BounceStats.Bounces, item.BounceStats.Sends)
115→			if item.DomainAuth != nil {
116→				fmt.Printf("    dns: mx=%t spf=%t dmarc=%t dkim=%s\n", item.DomainAuth.MXPresent, item.DomainAuth.SPFPresent, item.DomainAuth.DMARCPresent, item.DomainAuth.DKIMStatus)
117→				if item.DomainAuth.LookupError != "" {
118→					fmt.Printf("    dns note: %s\n", item.DomainAuth.LookupError)
119→				}
120→			}
121→			if item.Mailbox.LastBounceAt != "" {
122→				fmt.Printf("    last bounce: %s\n", shortDate(item.Mailbox.LastBounceAt))
123→			}
124→		}
125→		return nil
126→	},
127→}
