129→var mailboxesSetPolicyCmd = &cobra.Command{
130→	Use:   "set-policy <mailbox-email>",
131→	Short: "Update mailbox warmup, status, or daily caps",
132→	Args:  cobra.ExactArgs(1),
133→	RunE: func(cmd *cobra.Command, args []string) error {
134→		d, err := db.Open()
135→		if err != nil {
136→			return err
137→		}
138→		defer d.Close()
139→
140→		opts := sequence.MailboxPolicyOptions{
141→			Status:             mailboxSetStatus,
142→			TransportEmail:     mailboxSetTransportEmail,
143→			RotationGroup:      mailboxSetRotationGroup,
144→			WarmupStage:        mailboxSetWarmup,
145→			SendWindowTimezone: mailboxSendWindowTimezone,
146→			RestartWarmup:      mailboxRestartWarmup,
147→		}
148→		if mailboxFirstTouchCap >= 0 {
149→			opts.FirstTouchDailyCap = &mailboxFirstTouchCap
150→		}
151→		if mailboxFollowUpCap >= 0 {
152→			opts.FollowUpDailyCap = &mailboxFollowUpCap
153→		}
154→		if mailboxReplyCap >= 0 {
155→			opts.ReplyDailyCap = &mailboxReplyCap
156→		}
157→		if mailboxMinGapMinutes >= 0 {
158→			opts.MinGapMinutes = &mailboxMinGapMinutes
159→		}
160→		if mailboxSendWindowStart >= 0 {
161→			opts.SendWindowStartHour = &mailboxSendWindowStart
162→		}
163→		if mailboxSendWindowEnd >= 0 {
164→			opts.SendWindowEndHour = &mailboxSendWindowEnd
165→		}
166→		if mailboxReputationScore >= 0 {
167→			opts.ReputationScore = &mailboxReputationScore
168→		}
169→		if mailboxPriority >= 0 {
170→			opts.Priority = &mailboxPriority
171→		}
172→
173→		mailbox, err := sequence.UpdateMailboxPolicy(d, args[0], opts)
174→		if err != nil {
175→			return err
176→		}
177→
178→		fmt.Printf("  ✓ Updated %s\n", mailbox.Email)
179→		fmt.Printf("    status: %s | warmup: %s\n", mailbox.Status, mailbox.WarmupStage)
180→		fmt.Printf("    transport: %s | rotation: %s\n", mailbox.TransportEmail, mailbox.RotationGroup)
181→		fmt.Printf("    caps: first-touch=%d follow-up=%d reply=%d\n", mailbox.FirstTouchDailyCap, mailbox.FollowUpDailyCap, mailbox.ReplyDailyCap)
182→		fmt.Printf("    send window: %02d:00-%02d:00 %s\n", mailbox.SendWindowStartHour, mailbox.SendWindowEndHour, mailbox.SendWindowTimezone)
183→		fmt.Printf("    min gap: %d minutes | reputation: %d | priority: %d\n", mailbox.MinGapMinutes, mailbox.ReputationScore, mailbox.Priority)
184→		return nil
185→	},
186→}
187→
188→func init() {
189→	mailboxesCmd.PersistentFlags().StringVar(&mailboxesFormat, "format", "", "Output format (json)")
190→	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetStatus, "status", "", "Mailbox status (active, paused, unhealthy)")
191→	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetTransportEmail, "transport-email", "", "Transport identity used to send mail for this mailbox")
192→	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetRotationGroup, "rotation-group", "", "Rotation group used for mailbox fallback")
193→	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSetWarmup, "warmup", "", "Warmup stage label")
194→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxFirstTouchCap, "first-touch-cap", -1, "First-touch emails allowed per day")
195→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxFollowUpCap, "follow-up-cap", -1, "Follow-up emails allowed per day")
196→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxReplyCap, "reply-cap", -1, "Reply emails allowed per day (0 = unlimited)")
197→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxMinGapMinutes, "min-gap-minutes", -1, "Minimum minutes between sends")
198→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxSendWindowStart, "send-window-start", -1, "Allowed send window start hour in mailbox timezone (0-23)")
199→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxSendWindowEnd, "send-window-end", -1, "Allowed send window end hour in mailbox timezone (0-23)")
200→	mailboxesSetPolicyCmd.Flags().StringVar(&mailboxSendWindowTimezone, "send-window-timezone", "", "IANA timezone for the send window")
201→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxReputationScore, "reputation-score", -1, "Mailbox reputation score (0-100)")
202→	mailboxesSetPolicyCmd.Flags().IntVar(&mailboxPriority, "priority", -1, "Mailbox rotation priority")
203→	mailboxesSetPolicyCmd.Flags().BoolVar(&mailboxRestartWarmup, "restart-warmup", false, "Restart the mailbox warmup ramp from today")
204→	mailboxesHealthCmd.Flags().BoolVar(&mailboxesHealthDNS, "dns", true, "Include DNS auth checks for mailbox domains")
205→	mailboxesCmd.AddCommand(mailboxesStatusCmd)
206→	mailboxesCmd.AddCommand(mailboxesHealthCmd)
207→	mailboxesCmd.AddCommand(mailboxesSetPolicyCmd)
208→	rootCmd.AddCommand(mailboxesCmd)
209→}
