146→var sequenceTemplatesAddCmd = &cobra.Command{
147→	Use:   "add",
148→	Short: "Add or update a custom sequence template from JSON",
149→	RunE: func(cmd *cobra.Command, args []string) error {
150→		if sequenceTemplateFile == "" {
151→			return fmt.Errorf("--file is required")
152→		}
153→		data, err := os.ReadFile(sequenceTemplateFile)
154→		if err != nil {
155→			return err
156→		}
157→		var payload struct {
158→			Name        string                  `json:"name"`
159→			Description string                  `json:"description"`
160→			Steps       []sequence.TemplateStep `json:"steps"`
161→		}
162→		if err := json.Unmarshal(data, &payload); err != nil {
163→			return fmt.Errorf("parsing template JSON: %w", err)
164→		}
165→		description := payload.Description
166→		if sequenceTemplateDescription != "" {
167→			description = sequenceTemplateDescription
168→		}
169→
170→		d, err := db.Open()
171→		if err != nil {
172→			return err
173→		}
174→		defer d.Close()
175→
176→		record, err := sequence.SaveTemplate(d, sequence.Template{
177→			Name:  payload.Name,
178→			Steps: payload.Steps,
179→		}, description)
180→		if err != nil {
181→			return err
182→		}
183→		fmt.Printf("  ✓ Saved template %s (%d steps)\n", record.Name, len(record.Steps))
184→		return nil
185→	},
186→}
