110→func lookupDomainAuth(domain string) DomainAuthStatus {
111→	status := DomainAuthStatus{
112→		Domain:     domain,
113→		DKIMStatus: "unknown (selector-specific)",
114→	}
115→	if domain == "" {
116→		status.LookupError = "mailbox domain missing"
117→		return status
118→	}
119→
120→	if mx, err := net.LookupMX(domain); err == nil && len(mx) > 0 {
121→		status.MXPresent = true
122→	}
123→	txts, err := net.LookupTXT(domain)
124→	if err == nil {
125→		for _, txt := range txts {
126→			if strings.Contains(strings.ToLower(txt), "v=spf1") {
127→				status.SPFPresent = true
128→				break
129→			}
130→		}
131→	} else if status.LookupError == "" {
132→		status.LookupError = err.Error()
133→	}
134→
135→	dmarcTXT, err := net.LookupTXT("_dmarc." + domain)
136→	if err == nil {
137→		for _, txt := range dmarcTXT {
138→			if strings.Contains(strings.ToLower(txt), "v=dmarc1") {
139→				status.DMARCPresent = true
140→				break
141→			}
142→		}
143→	} else if status.LookupError == "" {
144→		status.LookupError = err.Error()
145→	}
146→
147→	return status
148→}
