1814→	if err != nil {
1815→		return "", "", err
1816→	}
1817→	step, ok := templateStep(template, task.StepNumber)
1818→	if !ok {
1819→		if subject == "" {
1820→			subject = enrollment.Subject
1821→		}
1822→		return subject, body, nil
1823→	}
1824→	renderedSubject, renderedBody := renderStep(step, *enrollment)
1825→	if subject == "" {
1826→		subject = renderedSubject
1827→	}
1828→	if body == "" {
1829→		body = renderedBody
1830→	}
1831→	return subject, body, nil
1832→}
