1917→func effectiveCaps(mailbox Mailbox, now time.Time) (int, int, int) {
1918→	if now.IsZero() {
1919→		now = time.Now()
1920→	}
1921→	firstTouchCap := mailbox.FirstTouchDailyCap
1922→	followUpCap := mailbox.FollowUpDailyCap
1923→	replyCap := mailbox.ReplyDailyCap
1924→
1925→	switch strings.ToLower(strings.TrimSpace(mailbox.WarmupStage)) {
1926→	case "warming":
1927→		day := warmupDay(mailbox, now)
1928→		firstTouchCap = minPositive(firstTouchCap, 3+day*2)
1929→		followUpCap = minPositive(followUpCap, 6+day*4)
1930→	case "ramping":
1931→		day := warmupDay(mailbox, now)
1932→		firstTouchCap = minPositive(firstTouchCap, 5+day*5)
1933→		followUpCap = minPositive(followUpCap, 10+day*10)
1934→	}
1935→
1936→	switch {
1937→	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 70:
1938→		firstTouchCap = scaledCap(firstTouchCap, 0.5)
1939→		followUpCap = scaledCap(followUpCap, 0.75)
1940→	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 85:
1941→		firstTouchCap = scaledCap(firstTouchCap, 0.75)
1942→	}
1943→
1944→	return firstTouchCap, followUpCap, replyCap
1945→}
