1965→func withinSendWindow(mailbox Mailbox, now time.Time) bool {
1966→	start := clampHour(mailbox.SendWindowStartHour)
1967→	end := clampHour(mailbox.SendWindowEndHour)
1968→	if start == end {
1969→		return true
1970→	}
1971→
1972→	loc := time.Local
1973→	tz := strings.TrimSpace(mailbox.SendWindowTimezone)
1974→	if tz != "" && !strings.EqualFold(tz, "local") {
1975→		if loaded, err := time.LoadLocation(tz); err == nil {
1976→			loc = loaded
1977→		}
1978→	}
1979→	hour := now.In(loc).Hour()
1980→	if start < end {
1981→		return hour >= start && hour < end
1982→	}
1983→	return hour >= start || hour < end
1984→}
