1996→func scaledCap(cap int, factor float64) int {
1997→	if cap <= 0 {
1998→		return cap
1999→	}
2000→	scaled := int(float64(cap) * factor)
2001→	if scaled < 1 {
2002→		scaled = 1
2003→	}
2004→	if scaled > cap {
2005→		scaled = cap
2006→	}
2007→	return scaled
2008→}
