2010→func minPositive(value, ceiling int) int {
2011→	if value <= 0 {
2012→		return value
2013→	}
2014→	if ceiling <= 0 {
2015→		return value
2016→	}
2017→	if value < ceiling {
2018→		return value
2019→	}
2020→	return ceiling
2021→}
