143→	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
144→	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")
145→
146→	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
147→		// Root command (init) skips auth — it's the first thing a user runs
148→		if cmd == rootCmd ||
149→			shouldSkipAuth(cmd) ||
150→			cmd.Name() == "help" ||
151→			cmd.Name() == "completion" {
152→			return nil
153→		}
154→		_, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL())
155→		return err
