159→// isKnownCommand checks if name matches any registered subcommand.
160→func isKnownCommand(name string) bool {
161→	for _, c := range rootCmd.Commands() {
162→		if c.Name() == name {
163→			return true
164→		}
165→		for _, alias := range c.Aliases {
166→			if alias == name {
167→				return true
168→			}
169→		}
170→	}
171→	return name == "help" || name == "completion"
172→}
