207→func readSkillContent(path string) (string, error) {
208→	var data []byte
209→	var err error
210→	if strings.TrimSpace(path) != "" {
211→		data, err = os.ReadFile(path)
212→		if err != nil {
213→			return "", fmt.Errorf("reading skill content: %w", err)
214→		}
215→	} else {
216→		data, err = io.ReadAll(os.Stdin)
217→		if err != nil {
218→			return "", fmt.Errorf("reading stdin: %w", err)
219→		}
220→	}
221→
222→	content := strings.TrimSpace(string(data))
223→	if content == "" {
224→		return "", fmt.Errorf("no skill content provided")
225→	}
226→	return content, nil
227→}
