 79→// sessionStatus holds workspace state gathered for banner/prompt output.
 80→type sessionStatus struct {
 81→	configLoaded          bool
 82→	setupCompleted        bool
 83→	connectors            map[string]project.ConnectorState
 84→	settings              map[string]string
 85→	emailTotal            int
 86→	outboundTotal         int
 87→	weeklyStats           *email.WeeklyStats
 88→	skillCount            int
 89→	skillNames            []string
 90→	contactCount          int
 91→	learningCount         int
 92→	recentStrategicMemory []session.StrategicMemory
 93→	staleSkills           []session.StaleSkill
 94→	startSync             *sessionSyncReport
 95→}
 96→
 97→type sessionSyncReport struct {
 98→	Attempted       bool                      `json:"attempted"`
 99→	RowsUpserted    int                       `json:"rows_upserted,omitempty"`
100→	TablesUpdated   int                       `json:"tables_updated,omitempty"`
101→	PreviousVersion int64                     `json:"previous_version,omitempty"`
102→	CurrentVersion  int64                     `json:"current_version,omitempty"`
103→	Delta           *nurgesync.ExecutionDelta `json:"delta,omitempty"`
104→	Error           string                    `json:"error,omitempty"`
105→}
106→
107→type sessionPushReport struct {
108→	Attempted     bool   `json:"attempted"`
109→	RowsPushed    int    `json:"rows_pushed,omitempty"`
110→	TablesScanned int    `json:"tables_scanned,omitempty"`
111→	Error         string `json:"error,omitempty"`
112→}
113→
114→func gatherStatus() *sessionStatus {
115→	s := &sessionStatus{
116→		settings: make(map[string]string),
117→	}
118→
119→	// Load config (graceful — may not exist)
120→	cfg, err := project.Load()
121→	if err == nil {
122→		s.configLoaded = true
123→		s.setupCompleted = cfg.SetupCompleted
124→		s.connectors = cfg.Connectors
125→		if cfg.Settings != nil {
126→			s.settings = cfg.Settings
127→		}
128→	}
129→
130→	// Load DB stats (graceful — may not exist)
131→	if !db.Exists() {
132→		return s
133→	}
134→	d, err := db.Open()
135→	if err != nil {
136→		return s
137→	}
138→	defer d.Close()
139→
140→	stats, err := email.Stats(d)
141→	if err == nil {
142→		s.emailTotal = stats.Total
143→		s.outboundTotal = stats.ByClass["outbound"]
144→	}
145→
146→	weekly, err := email.ThisWeek(d)
147→	if err == nil {
148→		s.weeklyStats = weekly
149→	}
150→
151→	skills, err := session.ListSkills(d)
152→	if err == nil {
153→		s.skillCount = len(skills)
154→		for _, sk := range skills {
155→			s.skillNames = append(s.skillNames, sk.SkillName)
156→		}
157→	}
158→
159→	// Contact count (graceful)
160→	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)
161→
162→	// Learning count (graceful)
163→	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)
164→
165→	memories, err := session.ListStrategicMemory(d, 3)
166→	if err == nil {
167→		s.recentStrategicMemory = memories
168→	}
169→
170→	staleSkills, err := session.ListStaleSkills(d, 5)
171→	if err == nil {
172→		s.staleSkills = staleSkills
173→	}
174→
175→	return s
176→}
