272→// runStop captures a stop event and creates a checkpoint.
273→func runStop() error {
274→	d, input, _ := openSessionDB()
275→	if d == nil {
276→		return nil
277→	}
278→	defer d.Close()
279→
280→	session.AddEvent(d, input.SessionID, "stop", input)
281→	if len(input.ModifiedFiles) > 0 {
282→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
283→	}
284→
285→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
286→	session.FlushLog()
287→	return nil
288→}
