290→// runSessionEnd marks a session as ended.
291→func runSessionEnd() error {
292→	d, input, _ := openSessionDB()
293→	if d == nil {
294→		return nil
295→	}
296→	defer d.Close()
297→
298→	session.EndSession(d, input.SessionID)
299→	session.AddEvent(d, input.SessionID, "session_end", input)
300→
301→	pushReport := attemptSessionEndPush(d)
302→	if pushReport.Attempted {
303→		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
304→		if pushReport.Error != "" {
305→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
306→		} else {
307→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
308→		}
309→	}
310→
311→	session.Logger().Info("session-end", "session_id", input.SessionID)
312→	session.FlushLog()
313→	return nil
314→}
