347→			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
348→		} else {
349→			b.WriteString("  Setup in progress.\n")
350→		}
351→		b.WriteString("  Run /nurge:setup to continue where you left off.")
352→		return b.String()
353→	}
354→
355→	// --- Post-setup: compact rotating dashboard ---
356→	name := s.settings["user.name"]
357→	if name != "" {
358→		fmt.Fprintf(&b, "  Hey %s\n", name)
359→	}
360→
361→	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
362→		fmt.Fprintf(&b, "  %s\n", syncLine)
363→	}
364→	if refreshLine := buildSkillRefreshBannerLine(s.staleSkills); refreshLine != "" {
365→		fmt.Fprintf(&b, "  %s\n", refreshLine)
