396→			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
397→		} else {
398→			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
399→		}
400→	case 1: // Data snapshot
401→		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
402→		if s.outboundTotal > 0 {
403→			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
