726→			fmt.Fprintf(&b, "- %s", memory.Summary)
727→			if len(memory.AffectedSkills) > 0 {
728→				fmt.Fprintf(&b, " Affects: %s.", strings.Join(memory.AffectedSkills, ", "))
729→			}
730→			b.WriteString("\n")
731→		}
732→	}
733→
734→	if len(staleSkills) > 0 {
735→		b.WriteString("Skills likely stale:\n")
736→		for _, item := range staleSkills {
737→			fmt.Fprintf(&b, "- %s: %s\n", item.SkillName, strings.Join(item.Reasons, "; "))
738→		}
739→		b.WriteString("If you refresh a skill, persist the new version with `nurge skills save <skill-name> --file .claude/skills/<skill-name>/SKILL.md`. Use `nurge skills stale --format json` for the full refresh list and `nurge memory list --format json` for the underlying strategic memory.\n")
740→	}
741→
742→	return b.String()
743→}
