149→			if item.BlockedReason != "" {
150→				fmt.Printf("    blocked: %s\n", item.BlockedReason)
151→			}
152→		}
153→
154→		if dispatcherExecute {
155→			var sentCount int
156→			for _, result := range results {
157→				if result.Status == "sent" {
158→					sentCount++
159→				}
160→			}
161→			fmt.Printf("\n  ✓ Executed %d due task(s)\n", sentCount)
162→			for _, result := range results {
