242→func executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
243→	results := make([]dispatcherExecutionResult, 0, len(dispatch))
244→	for _, item := range dispatch {
245→		if !item.Ready {
246→			continue
247→		}
248→
249→		attemptedAt := timeNow()
250→		fromAddress := strings.TrimSpace(item.TransportEmail)
251→		if fromAddress == "" {
252→			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
253→		}
254→		if fromAddress == "" {
255→			results = append(results, dispatcherExecutionResult{
256→				TaskID:       item.ID,
257→				ContactEmail: item.ContactEmail,
258→				MailboxEmail: item.SelectedMailboxEmail,
259→				Status:       "failed",
260→				Error:        "no transport address available for task",
261→			})
262→			continue
263→		}
264→
265→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
266→			To:       item.ContactEmail,
267→			Subject:  dispatchSubject(item),
268→			Body:     item.RenderedBody,
269→			ThreadID: item.ThreadID,
270→		})
271→		if err != nil {
272→			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
273→				return results, markErr
274→			}
275→			if updateErr := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusFailed, "", "", err.Error()); updateErr != nil {
276→				return results, updateErr
277→			}
278→			if logErr := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
279→				MailboxID:    item.SelectedMailboxID,
280→				EnrollmentID: item.EnrollmentID,
281→				TaskID:       item.ID,
282→				ContactEmail: item.ContactEmail,
283→				SendType:     item.SendType,
284→				Status:       "failed",
285→				Subject:      dispatchSubject(item),
286→				Error:        err.Error(),
287→				AttemptedAt:  attemptedAt,
288→			}); logErr != nil {
289→				return results, logErr
290→			}
291→			results = append(results, dispatcherExecutionResult{
292→				TaskID:       item.ID,
293→				ContactEmail: item.ContactEmail,
294→				MailboxEmail: item.SelectedMailboxEmail,
295→				Status:       "failed",
296→				Error:        err.Error(),
297→			})
298→			continue
299→		}
300→
301→		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
302→			return results, err
303→		}
304→		if err := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
305→			return results, err
306→		}
307→		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
308→			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
309→		}
310→		if err := email.StoreEmail(d, &email.RawMessage{
311→			ID:        sent.MessageID,
312→			Source:    "gmail",
313→			Direction: "outbound",
314→			ThreadID:  sent.ThreadID,
315→			Subject:   dispatchSubject(item),
316→			FromEmail: fromAddress,
317→			ToEmails:  recipientsJSON(item.ContactEmail),
318→			Date:      attemptedAt.UTC().Format(time.RFC3339),
319→			Labels:    `["SENT"]`,
320→		}); err != nil {
321→			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
322→		}
323→		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
324→			TaskID:    item.ID,
325→			ThreadID:  sent.ThreadID,
326→			MessageID: sent.MessageID,
327→			MailboxID: item.SelectedMailboxID,
328→			SentAt:    attemptedAt,
329→		}); err != nil {
330→			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
331→		}
332→		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
333→			MailboxID:    item.SelectedMailboxID,
334→			EnrollmentID: item.EnrollmentID,
335→			TaskID:       item.ID,
336→			ContactEmail: item.ContactEmail,
337→			SendType:     item.SendType,
338→			Status:       "sent",
339→			Subject:      dispatchSubject(item),
340→			MessageID:    sent.MessageID,
341→			AttemptedAt:  attemptedAt,
342→		}); err != nil {
343→			return results, err
344→		}
345→
346→		results = append(results, dispatcherExecutionResult{
347→			TaskID:       item.ID,
348→			ContactEmail: item.ContactEmail,
349→			MailboxEmail: item.SelectedMailboxEmail,
350→			MessageID:    sent.MessageID,
351→			Status:       "sent",
352→		})
353→	}
354→	return results, nil
355→}
