357→func preview(body string, limit int) string {
358→	body = strings.TrimSpace(body)
359→	body = strings.ReplaceAll(body, "\n", " ")
360→	if limit <= 0 || len(body) <= limit {
361→		return body
362→	}
363→	return body[:limit-1] + "…"
364→}
365→
366→func dispatchSubject(item sequence.DispatchTask) string {
367→	if strings.TrimSpace(item.RenderedSubject) != "" {
368→		return strings.TrimSpace(item.RenderedSubject)
369→	}
370→	return strings.TrimSpace(item.Subject)
371→}
372→
373→func shellSnippet(value string) string {
374→	if value == "" {
375→		return "''"
376→	}
377→	return "'" + strings.ReplaceAll(value, "'", `'"'"'`) + "'"
378→}
