118→      provider: "GOOGLE", // TODO: detect from payload
119→      email,
120→    });
121→
122→    return new Response("OK", { status: 200 });
123→  } catch (error: any) {
124→    console.error("Account callback error:", error);
125→    return new Response("Internal error", { status: 500 });
