106→		}
107→		json.Unmarshal(data, &errResp)
108→		return nil, fmt.Errorf("exchange failed: %s", errResp.Error)
109→	}
110→
111→	var result exchangeResponse
112→	if err := json.Unmarshal(data, &result); err != nil {
