 49→var dispatcherRunCmd = &cobra.Command{
 50→	Use:   "run",
 51→	Short: "Evaluate due sequence tasks against mailbox policy",
 52→	RunE: func(cmd *cobra.Command, args []string) error {
 53→		now := timeNow()
 54→
 55→		d, err := db.Open()
 56→		if err != nil {
 57→			return err
 58→		}
 59→		defer d.Close()
 60→
 61→		var cfg *project.Config
 62→		if dispatcherSyncReplies || dispatcherExecute || dispatcherTransportEmail != "" {
 63→			cfg, err = project.Load()
 64→			if err != nil {
 65→				return fmt.Errorf("loading config: %w", err)
 66→			}
 67→		}
 68→
 69→		transportEmail := strings.TrimSpace(dispatcherTransportEmail)
 70→		if transportEmail == "" && cfg != nil {
 71→			if gmail, ok := cfg.Connectors["gmail"]; ok && gmail.Connected {
 72→				transportEmail = gmail.Account
 73→			}
 74→		}
 75→
 76→		var gmailService *gm.Service
 77→		if dispatcherSyncReplies || dispatcherExecute {
 78→			if cfg == nil {
 79→				return fmt.Errorf("Gmail config is required for dispatcher execution")
 80→			}
 81→			gmail, ok := cfg.Connectors["gmail"]
 82→			if !ok || !gmail.Connected {
 83→				return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
 84→			}
 85→
 86→			gmailService, err = email.NewClient("")
 87→			if err != nil {
 88→				return fmt.Errorf("connecting to Gmail: %w", err)
 89→			}
 90→
 91→			if dispatcherSyncReplies {
 92→				if _, err := email.SyncReplies(gmailService, d, gmail.Account, now); err != nil {
 93→					return err
 94→				}
 95→			}
 96→		}
 97→
 98→		if dispatcherExecute && transportEmail == "" {
 99→			return fmt.Errorf("transport mailbox is required for --execute. Connect Gmail or pass --transport-email")
100→		}
101→
102→		dispatch, err := sequence.ListDispatchTasksForTransport(d, sequence.DispatchOptions{
103→			Limit:          dispatcherLimit,
104→			Now:            now,
105→			TransportEmail: transportEmail,
106→		})
107→		if err != nil {
108→			return err
109→		}
110→
111→		var results []dispatcherExecutionResult
112→		if dispatcherExecute {
113→			results, err = executeDispatch(gmailService, d, dispatch)
114→			if err != nil {
115→				return err
116→			}
117→		}
118→
119→		if dispatcherFormat == "json" {
120→			enc := json.NewEncoder(os.Stdout)
121→			enc.SetIndent("", "  ")
122→			return enc.Encode(dispatcherRunOutput{
123→				Queue:   dispatch,
124→				Results: results,
125→			})
126→		}
127→
128→		if len(dispatch) == 0 {
129→			fmt.Println("  ✓ No due tasks in the dispatcher queue")
130→			return nil
131→		}
132→
133→		for _, item := range dispatch {
134→			state := "ready"
135→			if !item.Ready {
136→				state = "blocked"
137→			}
138→			fmt.Printf("  [%s] %s\n", state, dispatchSubject(item))
139→			fmt.Printf("    task: %s (%s step %d)\n", item.ID, item.SequenceName, item.StepNumber)
140→			via := item.MailboxEmail
141→			if item.SelectedMailboxEmail != "" {
142→				via = item.SelectedMailboxEmail
143→			}
144→			fmt.Printf("    to: %s via %s\n", item.ContactEmail, via)
145→			fmt.Printf("    due: %s\n", shortDate(item.DueAt))
146→			if dispatcherExecute && item.RenderedBody != "" {
147→				fmt.Printf("    body: %s\n", preview(item.RenderedBody, 90))
148→			}
149→			if item.BlockedReason != "" {
150→				fmt.Printf("    blocked: %s\n", item.BlockedReason)
151→			}
152→		}
153→
154→		if dispatcherExecute {
155→			var sentCount int
156→			for _, result := range results {
157→				if result.Status == "sent" {
158→					sentCount++
159→				}
160→			}
161→			fmt.Printf("\n  ✓ Executed %d due task(s)\n", sentCount)
162→			for _, result := range results {
163→				fmt.Printf("    [%s] %s via %s\n", result.Status, result.ContactEmail, result.MailboxEmail)
164→				if result.Error != "" {
165→					fmt.Printf("      %s\n", result.Error)
166→				}
167→			}
168→		}
169→
170→		return nil
171→	},
172→}
