316→func buildBanner(s *sessionStatus) string {
317→	var b strings.Builder
318→	ver := fmt.Sprintf("nurge %s", buildVersion)
319→
320→	// Line 1: Powered by Nurge
321→	b.WriteString("\n\nPowered by Nurge\n")
322→	// Line 2: Version
323→	fmt.Fprintf(&b, "  %s\n", ver)
324→
325→	if !s.configLoaded {
326→		b.WriteString("  Run: nurge to get started")
327→		return b.String()
328→	}
329→
330→	// --- Pre-setup: no connectors yet ---
331→	hasConnectors := false
332→	for _, c := range s.connectors {
333→		if c.Connected {
334→			hasConnectors = true
335→			break
336→		}
337→	}
338→	if !hasConnectors {
339→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
340→		return b.String()
341→	}
342→
343→	// --- Setup in progress ---
344→	if !s.setupCompleted {
