644→func buildSyncPromptContext(report *sessionSyncReport) string {
645→	if report == nil || !report.Attempted {
646→		return ""
647→	}
648→
649→	var b strings.Builder
650→	if report.Error != "" {
651→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
652→		return b.String()
653→	}
654→
655→	if report.RowsUpserted == 0 {
656→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
657→		return b.String()
658→	}
659→
660→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
661→		report.RowsUpserted,
662→		pluralSuffix(report.RowsUpserted),
663→		report.TablesUpdated,
664→		pluralSuffix(report.TablesUpdated),
665→	)
666→
667→	if report.Delta == nil {
668→		return b.String()
669→	}
670→
671→	if report.Delta.TasksSent > 0 {
672→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
673→	}
674→	if report.Delta.TasksFailed > 0 {
675→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
676→	}
677→	if report.Delta.RepliesNeedingAttention > 0 {
678→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
679→		for _, item := range report.Delta.RecentReplies {
