682→				continue
683→			}
684→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
685→		}
686→	}
687→	if report.Delta.EnrollmentsStopped > 0 {
688→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
689→	}
690→	if report.Delta.EnrollmentsCompleted > 0 {
691→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
692→	}
693→	if report.Delta.SuppressionsAdded > 0 {
694→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
695→	}
696→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
697→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
698→	}
699→
700→	return b.String()
701→}
