 8→)
 9→
10→// AuthFile represents the local auth credentials stored at ~/.nurge/auth.json.
11→type AuthFile struct {
12→	Token       string `json:"token"`
13→	Email       string `json:"email"`
14→	Name        string `json:"name"`
15→	CreatedAt   string `json:"created_at,omitempty"`
16→	ValidatedAt string `json:"validated_at,omitempty"`
17→}
18→
19→func authDir() (string, error) {
20→	home, err := os.UserHomeDir()
21→	if err != nil {
22→		return "", fmt.Errorf("getting home directory: %w", err)
23→	}
24→	return filepath.Join(home, ".nurge"), nil
25→}
26→
27→func authFilePath() (string, error) {
28→	dir, err := authDir()
29→	if err != nil {
30→		return "", err
31→	}
32→	return filepath.Join(dir, "auth.json"), nil
33→}
34→
35→// LoadAuth reads the auth file from ~/.nurge/auth.json.
36→func LoadAuth() (*AuthFile, error) {
37→	path, err := authFilePath()
38→	if err != nil {
39→		return nil, err
40→	}
41→	data, err := os.ReadFile(path)
42→	if err != nil {
43→		return nil, fmt.Errorf("reading auth file: %w", err)
44→	}
45→	var af AuthFile
46→	if err := json.Unmarshal(data, &af); err != nil {
47→		return nil, fmt.Errorf("parsing auth file: %w", err)
48→	}
49→	return &af, nil
50→}
51→
52→// SaveAuth writes the auth file to ~/.nurge/auth.json.
53→// Creates ~/.nurge/ with 0700 if it doesn't exist.
54→// Writes auth.json with 0600 permissions.
55→func SaveAuth(af *AuthFile) error {
56→	dir, err := authDir()
57→	if err != nil {
58→		return err
59→	}
60→	if err := os.MkdirAll(dir, 0700); err != nil {
61→		return fmt.Errorf("creating auth directory: %w", err)
62→	}
63→
64→	data, err := json.MarshalIndent(af, "", "  ")
65→	if err != nil {
66→		return fmt.Errorf("marshaling auth file: %w", err)
67→	}
68→
69→	path := filepath.Join(dir, "auth.json")
70→	if err := os.WriteFile(path, data, 0600); err != nil {
71→		return fmt.Errorf("writing auth file: %w", err)
72→	}
73→	return nil
74→}
75→
76→// DeleteAuth removes ~/.nurge/auth.json.
77→func DeleteAuth() error {
78→	path, err := authFilePath()
79→	if err != nil {
80→		return err
81→	}
82→	if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
83→		return fmt.Errorf("deleting auth file: %w", err)
84→	}
85→	return nil
86→}
