  4→export async function authenticateUser(
  5→  ctx: QueryCtx | MutationCtx,
  6→  token: string
  7→): Promise<string> {
  8→  const user = await ctx.db
  9→    .query("users")
 10→    .withIndex("by_token", (q) => q.eq("token", token))
 11→    .first();
 12→  if (!user) {
 13→    throw new Error("Invalid auth token");
 14→  }
 15→  return user._id;
 16→}
 17→
 18→// Get next sync version for a user and increment it.
 19→export async function nextSyncVersion(
 20→  ctx: MutationCtx,
 21→  userId: string
 22→): Promise<number> {
 23→  const syncState = await ctx.db
 24→    .query("syncState")
 25→    .withIndex("by_user", (q) => q.eq("userId", userId))
 26→    .first();
 27→
 28→  const next = (syncState?.lastSyncVersion ?? 0) + 1;
 29→
 30→  if (syncState) {
 31→    await ctx.db.patch(syncState._id, { lastSyncVersion: next });
 32→  } else {
 33→    await ctx.db.insert("syncState", { userId, lastSyncVersion: next });
 34→  }
 35→
 36→  return next;
 37→}
 38→
 39→// Check if a contact is suppressed (by email or domain).
 40→export async function isSuppressed(
 41→  ctx: QueryCtx,
 42→  userId: string,
 43→  email: string
 44→): Promise<{ suppressed: boolean; reason?: string }> {
 45→  // Check email suppression
 46→  const emailSup = await ctx.db
 47→    .query("suppressions")
 48→    .withIndex("by_lookup", (q) =>
 49→      q.eq("userId", userId).eq("scope", "email").eq("value", email)
 50→    )
 51→    .first();
 52→  if (emailSup) {
 53→    return { suppressed: true, reason: emailSup.reason };
 54→  }
 55→
 56→  // Check domain suppression
 57→  const domain = email.split("@")[1];
 58→  if (domain) {
 59→    const domainSup = await ctx.db
 60→      .query("suppressions")
 61→      .withIndex("by_lookup", (q) =>
 62→        q.eq("userId", userId).eq("scope", "domain").eq("value", domain)
 63→      )
 64→      .first();
 65→    if (domainSup) {
 66→      return { suppressed: true, reason: domainSup.reason };
 67→    }
 68→  }
 69→
 70→  return { suppressed: false };
 71→}
