 90→// Get today's date string in YYYY-MM-DD format for a given timezone.
 91→export function todayInTimezone(timezone: string): string {
 92→  try {
 93→    const now = new Date();
 94→    const formatted = now.toLocaleDateString("en-CA", { timeZone: timezone });
 95→    return formatted; // en-CA gives YYYY-MM-DD format
 96→  } catch {
 97→    // Fallback to UTC
 98→    return new Date().toISOString().split("T")[0];
 99→  }
100→}
101→
102→// Check if current time is within the mailbox send window.
103→export function withinSendWindow(
104→  startHour: number,
105→  endHour: number,
106→  timezone: string
107→): boolean {
108→  try {
109→    const now = new Date();
110→    const hourStr = now.toLocaleString("en-US", {
111→      timeZone: timezone,
112→      hour: "numeric",
113→      hour12: false,
114→    });
115→    const hour = parseInt(hourStr, 10);
116→    return hour >= startHour && hour < endHour;
117→  } catch {
118→    return true; // If timezone is invalid, allow sending
119→  }
120→}
