 13→// Create enrollment + drafts after first touch send intent
 14→export const createEnrollment = mutation({
 15→  args: {
 16→    userId: v.string(),
 17→    enrollment: v.object({
 18→      externalId: v.string(),
 19→      sequenceName: v.string(),
 20→      campaignName: v.optional(v.string()),
 21→      mailboxId: v.string(),
 22→      contactEmail: v.string(),
 23→      contactName: v.optional(v.string()),
 24→      subject: v.optional(v.string()),
 25→      threadId: v.optional(v.string()),
 26→      lastMessageId: v.optional(v.string()),
 27→      currentStep: v.float64(),
 28→      totalSteps: v.float64(),
 29→      initialBody: v.optional(v.string()),
 30→      unipileThreadProviderId: v.optional(v.string()),
 31→      unipileAccountId: v.optional(v.string()),
 32→    }),
 33→    task: v.object({
 34→      externalId: v.string(),
 35→      stepNumber: v.float64(),
 36→      stepName: v.optional(v.string()),
 37→      sendType: v.string(),
 38→      dueAt: v.string(),
 39→      subject: v.optional(v.string()),
 40→      body: v.optional(v.string()),
 41→    }),
 42→    drafts: v.array(
 43→      v.object({
 44→        externalId: v.string(),
 45→        taskId: v.string(),
 46→        stepNumber: v.float64(),
 47→        subject: v.optional(v.string()),
 48→        body: v.optional(v.string()),
 49→        channel: v.string(),
 50→        generatedBy: v.optional(v.string()),
 51→        generatedContext: v.optional(v.string()),
 52→      })
 53→    ),
 54→  },
 55→  handler: async (ctx, args) => {
 56→    const version = await nextSyncVersion(ctx, args.userId);
 57→
 58→    // Create enrollment
 59→    await ctx.db.insert("sequenceEnrollments", {
 60→      ...args.enrollment,
 61→      status: "active",
 62→      statusReason: "",
 63→      replyState: "",
 64→      lastSentAt: new Date().toISOString(),
 65→      nextDueAt: args.task.dueAt,
 66→      syncVersion: version,
 67→      userId: args.userId,
 68→    });
 69→
 70→    // Create first follow-up task
 71→    await ctx.db.insert("followUpTasks", {
 72→      externalId: args.task.externalId,
 73→      enrollmentId: args.enrollment.externalId,
 74→      mailboxId: args.enrollment.mailboxId,
 75→      contactEmail: args.enrollment.contactEmail,
 76→      subject: args.task.subject,
 77→      body: args.task.body,
 78→      threadId: args.enrollment.threadId,
 79→      stepNumber: args.task.stepNumber,
 80→      stepName: args.task.stepName,
 81→      sendType: args.task.sendType,
 82→      status: "open",
 83→      sendStatus: "pending",
 84→      dueAt: args.task.dueAt,
 85→      attemptCount: 0,
 86→      syncVersion: version,
 87→      userId: args.userId,
 88→    });
 89→
 90→    // Create drafts for future steps
 91→    for (const draft of args.drafts) {
 92→      await ctx.db.insert("sequenceDrafts", {
 93→        externalId: draft.externalId,
 94→        enrollmentId: args.enrollment.externalId,
 95→        taskId: draft.taskId,
 96→        stepNumber: draft.stepNumber,
 97→        subject: draft.subject,
 98→        body: draft.body,
 99→        channel: draft.channel,
100→        status: "pending",
101→        generatedBy: draft.generatedBy,
102→        generatedContext: draft.generatedContext,
103→        syncVersion: version,
104→        userId: args.userId,
105→      });
106→    }
107→
108→    return { enrollmentId: args.enrollment.externalId, version };
109→  },
110→});
