112→// Stop enrollment with status priority enforcement
113→export const stopEnrollment = mutation({
114→  args: {
115→    userId: v.string(),
116→    enrollmentId: v.string(),
117→    reason: v.optional(v.string()),
118→    addSuppression: v.optional(
119→      v.object({
120→        scope: v.string(),
121→        value: v.string(),
122→        reason: v.optional(v.string()),
123→        source: v.string(),
124→        externalId: v.string(),
125→      })
126→    ),
127→  },
128→  handler: async (ctx, args) => {
129→    const version = await nextSyncVersion(ctx, args.userId);
130→
131→    const enrollment = await ctx.db
132→      .query("sequenceEnrollments")
133→      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
134→      .first();
135→
136→    if (!enrollment) {
137→      throw new Error(`Enrollment ${args.enrollmentId} not found`);
138→    }
139→
140→    // Status priority check
141→    const currentPriority = STATUS_PRIORITY[enrollment.status] ?? 0;
142→    const newPriority = STATUS_PRIORITY["stopped"] ?? 3;
143→    if (currentPriority >= newPriority) {
144→      return { already: enrollment.status };
145→    }
146→
147→    await ctx.db.patch(enrollment._id, {
148→      status: "stopped",
149→      statusReason: args.reason || "manual stop",
150→      nextDueAt: "",
151→      syncVersion: version,
152→    });
153→
154→    // Cancel all pending tasks for this enrollment
155→    const tasks = await ctx.db
156→      .query("followUpTasks")
157→      .withIndex("by_enrollment", (q) => q.eq("enrollmentId", args.enrollmentId))
158→      .collect();
159→
160→    for (const task of tasks) {
161→      if (task.status === "open" && task.sendStatus === "pending") {
162→        await ctx.db.patch(task._id, {
163→          status: "canceled",
164→          sendStatus: "canceled",
165→          canceledReason: args.reason || "enrollment stopped",
166→          syncVersion: version,
167→        });
168→      }
169→    }
170→
171→    // Cancel pending drafts
172→    const drafts = await ctx.db
173→      .query("sequenceDrafts")
174→      .withIndex("by_enrollment", (q) => q.eq("enrollmentId", args.enrollmentId))
175→      .collect();
176→
177→    for (const draft of drafts) {
178→      if (draft.status === "pending") {
179→        await ctx.db.patch(draft._id, {
180→          status: "canceled",
181→          syncVersion: version,
182→        });
183→      }
184→    }
185→
186→    // Optionally add suppression
187→    if (args.addSuppression) {
188→      await ctx.db.insert("suppressions", {
189→        externalId: args.addSuppression.externalId,
190→        scope: args.addSuppression.scope,
191→        value: args.addSuppression.value,
192→        reason: args.addSuppression.reason || "",
193→        source: args.addSuppression.source,
194→        syncVersion: version,
195→        userId: args.userId,
196→      });
197→    }
198→
199→    return { stopped: true, version };
200→  },
201→});
202→
203→// Pause enrollment
204→export const pauseEnrollment = mutation({
205→  args: {
206→    userId: v.string(),
207→    enrollmentId: v.string(),
208→  },
209→  handler: async (ctx, args) => {
210→    const version = await nextSyncVersion(ctx, args.userId);
211→
212→    const enrollment = await ctx.db
213→      .query("sequenceEnrollments")
214→      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
215→      .first();
216→
217→    if (!enrollment) {
218→      throw new Error(`Enrollment ${args.enrollmentId} not found`);
219→    }
220→
221→    // Status priority: can only pause if currently active
222→    if (STATUS_PRIORITY[enrollment.status] > STATUS_PRIORITY["paused"]) {
223→      return { rejected: true, currentStatus: enrollment.status };
224→    }
225→
226→    await ctx.db.patch(enrollment._id, {
227→      status: "paused",
228→      statusReason: "manual pause",
229→      syncVersion: version,
230→    });
231→
232→    return { paused: true, version };
233→  },
234→});
235→
236→// Resume enrollment
237→export const resumeEnrollment = mutation({
238→  args: {
239→    userId: v.string(),
240→    enrollmentId: v.string(),
241→  },
242→  handler: async (ctx, args) => {
243→    const version = await nextSyncVersion(ctx, args.userId);
244→
245→    const enrollment = await ctx.db
246→      .query("sequenceEnrollments")
247→      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
248→      .first();
249→
250→    if (!enrollment) {
251→      throw new Error(`Enrollment ${args.enrollmentId} not found`);
252→    }
253→
254→    if (enrollment.status !== "paused") {
255→      return { rejected: true, currentStatus: enrollment.status };
256→    }
257→
258→    await ctx.db.patch(enrollment._id, {
259→      status: "active",
260→      statusReason: "",
261→      syncVersion: version,
262→    });
263→
264→    return { resumed: true, version };
265→  },
266→});
