 5→	"fmt"
 6→	"strings"
 7→
 8→	gm "google.golang.org/api/gmail/v1"
 9→)
10→
11→// SendOptions holds the fields for composing an email.
12→type SendOptions struct {
13→	To       string // recipient email
14→	Cc       string // optional CC
15→	Subject  string
16→	Body     string // plain text body
17→	ThreadID string
18→}
19→
20→type SentMessage struct {
21→	MessageID string
22→	ThreadID  string
23→}
24→
25→// Send sends an email via the Gmail API.
26→func Send(srv *gm.Service, from string, opts SendOptions) (*SentMessage, error) {
27→	if opts.To == "" {
28→		return nil, fmt.Errorf("recipient (--to) is required")
29→	}
30→	if opts.Subject == "" {
31→		return nil, fmt.Errorf("subject (--subject) is required")
32→	}
33→	if opts.Body == "" {
34→		return nil, fmt.Errorf("body (--body) is required")
35→	}
36→
37→	raw := buildRawMessage(from, opts)
38→	msg := &gm.Message{
39→		Raw: base64.URLEncoding.EncodeToString([]byte(raw)),
40→	}
41→	if opts.ThreadID != "" {
42→		msg.ThreadId = opts.ThreadID
43→	}
44→
45→	sent, err := srv.Users.Messages.Send("me", msg).Do()
46→	if err != nil {
47→		return nil, fmt.Errorf("sending email: %w", err)
48→	}
49→
50→	return &SentMessage{
51→		MessageID: sent.Id,
52→		ThreadID:  sent.ThreadId,
53→	}, nil
54→}
55→
56→func buildRawMessage(from string, opts SendOptions) string {
57→	var b strings.Builder
58→	b.WriteString("From: " + from + "\r\n")
59→	b.WriteString("To: " + opts.To + "\r\n")
60→	if opts.Cc != "" {
61→		b.WriteString("Cc: " + opts.Cc + "\r\n")
62→	}
63→	b.WriteString("Subject: " + opts.Subject + "\r\n")
64→	b.WriteString("MIME-Version: 1.0\r\n")
65→	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
66→	b.WriteString("\r\n")
67→	b.WriteString(opts.Body)
68→	return b.String()
69→}
