  5→// Request a Unipile hosted auth link for connecting Gmail or LinkedIn
  6→export const requestConnectionLink = action({
  7→  args: {
  8→    userId: v.string(),
  9→    provider: v.string(), // GOOGLE | LINKEDIN
 10→  },
 11→  handler: async (ctx, args) => {
 12→    const apiKey = process.env.UNIPILE_API_KEY;
 13→    const apiUrl = process.env.UNIPILE_API_URL;
 14→    const convexSiteUrl = process.env.CONVEX_SITE_URL;
 15→
 16→    if (!apiKey || !apiUrl) {
 17→      throw new Error("Unipile API key or URL not configured");
 18→    }
 19→
 20→    const notifyUrl = `${convexSiteUrl}/api/unipile-account-callback`;
 21→
 22→    const resp = await fetch(`${apiUrl}/api/v1/hosted/request_link`, {
 23→      method: "POST",
 24→      headers: {
 25→        "X-API-KEY": apiKey,
 26→        "Content-Type": "application/json",
 27→      },
 28→      body: JSON.stringify({
 29→        type: "create",
 30→        providers: [args.provider],
 31→        notify_url: notifyUrl,
 32→        name: args.userId, // Pass user ID for matching on callback
 33→        expiresOn: new Date(Date.now() + 30 * 60 * 1000).toISOString(), // 30 min expiry
 34→      }),
 35→    });
 36→
 37→    if (!resp.ok) {
 38→      const error = await resp.text();
 39→      throw new Error(`Unipile request_link failed: ${error}`);
 40→    }
 41→
 42→    const result = await resp.json();
 43→    return { url: result.url };
 44→  },
 45→});
 46→
 47→// Backfill emails from Unipile (90 days of sent history)
 48→export const backfillEmails = action({
 49→  args: {
 50→    userId: v.string(),
 51→    unipileAccountId: v.string(),
 52→  },
 53→  handler: async (ctx, args) => {
 54→    const apiKey = process.env.UNIPILE_API_KEY;
 55→    const apiUrl = process.env.UNIPILE_API_URL;
 56→
 57→    if (!apiKey || !apiUrl) {
 58→      throw new Error("Unipile API key or URL not configured");
 59→    }
 60→
 61→    const since = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
 62→    let cursor: string | undefined;
 63→    let totalFetched = 0;
 64→
 65→    do {
 66→      const params = new URLSearchParams({
 67→        account_id: args.unipileAccountId,
 68→        folder: "SENT",
 69→        after: since,
 70→        limit: "100",
 71→      });
 72→      if (cursor) {
 73→        params.set("cursor", cursor);
 74→      }
 75→
 76→      const resp = await fetch(`${apiUrl}/api/v1/emails?${params}`, {
 77→        headers: { "X-API-KEY": apiKey },
 78→      });
 79→
 80→      if (!resp.ok) {
 81→        const error = await resp.text();
 82→        throw new Error(`Unipile email list failed: ${error}`);
 83→      }
 84→
 85→      const result = await resp.json();
 86→      const emails = result.items || result.data || [];
 87→
 88→      if (emails.length === 0) break;
 89→
 90→      // Store emails in Convex (batch)
 91→      for (const email of emails) {
 92→        const toEmails = (email.to || []).map(
 93→          (t: any) => t.identifier || t.email || ""
 94→        );
 95→        const ccEmails = (email.cc || []).map(
 96→          (c: any) => c.identifier || c.email || ""
 97→        );
 98→
 99→        await ctx.runMutation(internal.unipile.storeEmail, {
100→          userId: args.userId,
101→          email: {
102→            externalId: email.id || `uni-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
103→            source: "unipile",
104→            direction: "outbound",
105→            threadId: email.thread_id || "",
106→            subject: email.subject || "",
107→            fromEmail: email.from?.identifier || "",
108→            toEmails: JSON.stringify(toEmails),
109→            ccEmails: JSON.stringify(ccEmails),
110→            date: email.date || new Date().toISOString(),
111→            snippet: email.body_plain?.substring(0, 200) || "",
112→            unipileId: email.id || "",
113→            providerId: email.provider_id
114→              ? JSON.stringify(email.provider_id)
115→              : "",
116→            unipileAccountId: args.unipileAccountId,
117→          },
118→        });
119→        totalFetched++;
120→      }
121→
122→      cursor = result.cursor || result.next_cursor;
123→    } while (cursor);
124→
125→    return { totalFetched };
126→  },
127→});
128→
129→export const storeEmail = internalMutation({
130→  args: {
131→    userId: v.string(),
132→    email: v.object({
133→      externalId: v.string(),
134→      source: v.string(),
135→      direction: v.string(),
136→      threadId: v.string(),
137→      subject: v.optional(v.string()),
138→      fromEmail: v.string(),
139→      toEmails: v.string(),
140→      ccEmails: v.optional(v.string()),
141→      date: v.string(),
142→      snippet: v.optional(v.string()),
143→      unipileId: v.optional(v.string()),
144→      providerId: v.optional(v.string()),
145→      unipileAccountId: v.optional(v.string()),
146→    }),
147→  },
148→  handler: async (ctx, args) => {
149→    // Check if email already exists
150→    const existing = await ctx.db
151→      .query("emails")
152→      .withIndex("by_external_id", (q) =>
153→        q.eq("externalId", args.email.externalId)
154→      )
155→      .first();
156→
157→    const syncState = await ctx.db
158→      .query("syncState")
159→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
160→      .first();
161→    const version = (syncState?.lastSyncVersion ?? 0) + 1;
162→
163→    if (existing) {
164→      await ctx.db.patch(existing._id, {
165→        ...args.email,
166→        syncVersion: version,
167→      });
168→    } else {
169→      await ctx.db.insert("emails", {
170→        ...args.email,
171→        class: "unclassified",
172→        syncVersion: version,
173→        userId: args.userId,
174→      });
175→    }
176→
177→    if (syncState) {
178→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
179→    } else {
180→      await ctx.db.insert("syncState", {
181→        userId: args.userId,
182→        lastSyncVersion: version,
183→      });
184→    }
185→  },
186→});
