  7→  args: {
  8→    userId: v.string(),
  9→    taskId: v.string(), // externalId of follow_up_task
 10→    accountId: v.string(), // Unipile account ID
 11→    to: v.string(),
 12→    subject: v.string(),
 13→    body: v.string(),
 14→    replyTo: v.optional(v.string()), // provider_id for threading
 15→  },
 16→  handler: async (ctx, args) => {
 17→    const apiKey = process.env.UNIPILE_API_KEY;
 18→    const apiUrl = process.env.UNIPILE_API_URL;
 19→    if (!apiKey || !apiUrl) {
 20→      // Record failure
 21→      await ctx.runMutation(internal.send.recordSendFailure, {
 22→        userId: args.userId,
 23→        taskId: args.taskId,
 24→        error: "Unipile API key or URL not configured",
 25→      });
 26→      return { ok: false, error: "Unipile not configured" };
 27→    }
 28→
 29→    try {
 30→      const payload: Record<string, any> = {
 31→        account_id: args.accountId,
 32→        to: [{ identifier: args.to }],
 33→        subject: args.subject,
 34→        body: args.body,
 35→      };
 36→
 37→      if (args.replyTo) {
 38→        payload.reply_to = args.replyTo;
 39→      }
 40→
 41→      const resp = await fetch(`${apiUrl}/api/v1/emails`, {
 42→        method: "POST",
 43→        headers: {
 44→          "X-API-KEY": apiKey,
 45→          "Content-Type": "application/json",
 46→        },
 47→        body: JSON.stringify(payload),
 48→      });
 49→
 50→      if (!resp.ok) {
 51→        const errorText = await resp.text();
 52→
 53→        // Check for auth errors
 54→        if (resp.status === 401 || resp.status === 403) {
 55→          await ctx.runMutation(internal.send.recordAuthFailure, {
 56→            userId: args.userId,
 57→            taskId: args.taskId,
 58→            mailboxId: "", // will be resolved in mutation
 59→            error: `Auth error: ${errorText}`,
 60→          });
 61→          return { ok: false, error: `Auth error: ${resp.status}` };
 62→        }
 63→
 64→        await ctx.runMutation(internal.send.recordSendFailure, {
 65→          userId: args.userId,
 66→          taskId: args.taskId,
 67→          error: `Unipile API error ${resp.status}: ${errorText}`,
 68→        });
 69→        return { ok: false, error: errorText };
 70→      }
 71→
 72→      const result = await resp.json();
 73→
 74→      // Record success
 75→      await ctx.runMutation(internal.send.recordSendSuccess, {
 76→        userId: args.userId,
 77→        taskId: args.taskId,
 78→        unipileMessageId: result.id || "",
 79→        providerId: JSON.stringify(result.provider_id || ""),
 80→      });
 81→
 82→      return { ok: true, messageId: result.id, providerId: result.provider_id };
 83→    } catch (error: any) {
 84→      await ctx.runMutation(internal.send.recordSendFailure, {
 85→        userId: args.userId,
 86→        taskId: args.taskId,
 87→        error: error.message || "Unknown error",
 88→      });
 89→      return { ok: false, error: error.message };
 90→    }
 91→  },
 92→});
