254→export const markMailboxAuthExpired = internalMutation({
255→  args: { userId: v.string(), unipileAccountId: v.string() },
256→  handler: async (ctx, args) => {
257→    // Find mailbox by Unipile account
258→    const account = await ctx.db
259→      .query("unipileAccounts")
260→      .withIndex("by_unipile_id", (q) =>
261→        q.eq("unipileAccountId", args.unipileAccountId)
262→      )
263→      .first();
264→
265→    if (account) {
266→      await ctx.db.patch(account._id, { status: "auth_expired" });
267→    }
268→
269→    // Find mailboxes associated with this account and mark them
270→    const mailboxes = await ctx.db
271→      .query("mailboxes")
272→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
273→      .collect();
274→
275→    const syncState = await ctx.db
276→      .query("syncState")
277→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
278→      .first();
279→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
280→
281→    for (const mailbox of mailboxes) {
282→      if (mailbox.status === "active") {
283→        await ctx.db.patch(mailbox._id, {
284→          status: "auth_expired",
285→          syncVersion: version,
286→        });
287→        version++;
288→      }
289→    }
290→
291→    if (syncState) {
292→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
293→    } else {
294→      await ctx.db.insert("syncState", {
295→        userId: args.userId,
296→        lastSyncVersion: version,
297→      });
298→    }
299→  },
300→});
