  1→import { v } from "convex/values";
  2→import { httpAction } from "./_generated/server";
  3→import { mutation, query } from "./_generated/server";
  4→
  5→// Table name mapping: Convex table names (camelCase) ↔ SQLite table names (snake_case)
  6→const TABLE_MAP: Record<string, string> = {
  7→  emails: "emails",
  8→  mailboxes: "mailboxes",
  9→  mailboxSendEvents: "mailbox_send_events",
 10→  sequenceEnrollments: "sequence_enrollments",
 11→  followUpTasks: "follow_up_tasks",
 12→  suppressions: "suppressions",
 13→  replyEvents: "reply_events",
 14→  sequenceDrafts: "sequence_drafts",
 15→  contacts: "contacts",
 16→  learnings: "learnings",
 17→  skillVersions: "skill_versions",
 18→  deals: "deals",
 19→};
 20→
 21→const EXECUTION_TABLES = [
 22→  "emails",
 23→  "mailboxes",
 24→  "mailboxSendEvents",
 25→  "sequenceEnrollments",
 26→  "followUpTasks",
 27→  "suppressions",
 28→  "replyEvents",
 29→  "sequenceDrafts",
 30→] as const;
 31→
 32→// Pull execution state — CLI calls this to mirror Convex → SQLite
 33→export const pullExecutionState = query({
 34→  args: {
 35→    userId: v.string(),
 36→    syncVersion: v.float64(),
 37→  },
 38→  handler: async (ctx, args) => {
 39→    const rows: Array<{ table: string; id: string; data: Record<string, any>; version: number }> = [];
 40→
 41→    for (const table of EXECUTION_TABLES) {
 42→      const results = await ctx.db
 43→        .query(table)
 44→        .withIndex("by_user", (q) => q.eq("userId", args.userId))
 45→        .filter((q) => q.gt(q.field("syncVersion"), args.syncVersion))
 46→        .collect();
 47→
 48→      for (const row of results) {
 49→        const { _id, _creationTime, userId, ...data } = row;
 50→        rows.push({
 51→          table: TABLE_MAP[table] || table,
 52→          id: row.externalId as string,
 53→          data,
 54→          version: row.syncVersion as number,
 55→        });
 56→      }
 57→    }
 58→
 59→    // Find the max sync version across all returned rows
 60→    let maxVersion = args.syncVersion;
 61→    for (const row of rows) {
 62→      if (row.version > maxVersion) {
 63→        maxVersion = row.version;
 64→      }
 65→    }
 66→
 67→    return { rows, sync_version: maxVersion };
 68→  },
 69→});
 70→
 71→// Push local state — CLI calls this to push SQLite → Convex
 72→export const pushLocalState = mutation({
 73→  args: {
 74→    userId: v.string(),
 75→    rows: v.array(
 76→      v.object({
 77→        table: v.string(),
 78→        id: v.string(),
 79→        data: v.any(),
 80→      })
 81→    ),
 82→  },
 83→  handler: async (ctx, args) => {
 84→    const versions: Record<string, number> = {};
 85→
 86→    // Get current max sync version
 87→    const syncState = await ctx.db
 88→      .query("syncState")
 89→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
 90→      .first();
 91→
 92→    let currentVersion = syncState?.lastSyncVersion ?? 0;
 93→
 94→    // Reverse map: snake_case → camelCase
 95→    const reverseTableMap: Record<string, string> = {};
 96→    for (const [convex, sqlite] of Object.entries(TABLE_MAP)) {
 97→      reverseTableMap[sqlite] = convex;
 98→    }
 99→
100→    for (const row of args.rows) {
101→      const convexTable = reverseTableMap[row.table] || row.table;
102→      currentVersion++;
103→
104→      // Check if row exists
105→      const existing = await ctx.db
106→        .query(convexTable as any)
107→        .withIndex("by_external_id", (q) => q.eq("externalId", row.id))
108→        .first();
109→
110→      const rowData = {
111→        ...(row.data as Record<string, any>),
112→        externalId: row.id,
113→        syncVersion: currentVersion,
114→        userId: args.userId,
115→      };
116→
117→      if (existing) {
118→        await ctx.db.patch(existing._id, rowData);
119→      } else {
120→        await ctx.db.insert(convexTable as any, rowData);
121→      }
122→
123→      versions[row.id] = currentVersion;
124→    }
125→
126→    // Update sync state
127→    if (syncState) {
128→      await ctx.db.patch(syncState._id, { lastSyncVersion: currentVersion });
129→    } else {
130→      await ctx.db.insert("syncState", {
131→        userId: args.userId,
132→        lastSyncVersion: currentVersion,
133→      });
134→    }
135→
136→    return { versions };
137→  },
138→});
