134→func CampaignMailbox(d *sql.DB, campaign *Campaign) (*Mailbox, error) {
135→	if campaign == nil || campaign.MailboxID == "" {
136→		return nil, nil
137→	}
138→	return mailboxByID(d, campaign.MailboxID)
