 11→type BounceStats struct {
 12→	WindowDays int     `json:"window_days"`
 13→	Sends      int     `json:"sends"`
 14→	Bounces    int     `json:"bounces"`
 15→	BounceRate float64 `json:"bounce_rate"`
 16→}
 17→
 18→type DomainAuthStatus struct {
 19→	Domain       string `json:"domain"`
 20→	MXPresent    bool   `json:"mx_present"`
 21→	SPFPresent   bool   `json:"spf_present"`
 22→	DMARCPresent bool   `json:"dmarc_present"`
 23→	DKIMStatus   string `json:"dkim_status"`
 24→	LookupError  string `json:"lookup_error,omitempty"`
 25→}
