 27→type MailboxHealth struct {
 28→	Mailbox                MailboxStatus     `json:"mailbox"`
 29→	WarmupDay              int               `json:"warmup_day"`
 30→	EffectiveFirstTouchCap int               `json:"effective_first_touch_cap"`
 31→	EffectiveFollowUpCap   int               `json:"effective_follow_up_cap"`
 32→	EffectiveReplyCap      int               `json:"effective_reply_cap"`
 33→	BounceStats            BounceStats       `json:"bounce_stats"`
 34→	HealthScore            int               `json:"health_score"`
 35→	Risk                   string            `json:"risk"`
 36→	DomainAuth             *DomainAuthStatus `json:"domain_auth,omitempty"`
 37→}
 38→
 39→func ListMailboxHealth(d *sql.DB, now time.Time, withDNS bool) ([]MailboxHealth, error) {
 40→	if now.IsZero() {
 41→		now = time.Now()
 42→	}
 43→
 44→	mailboxes, err := ListMailboxes(d, now)
 45→	if err != nil {
 46→		return nil, err
 47→	}
 48→
 49→	items := make([]MailboxHealth, 0, len(mailboxes))
 50→	for _, mailbox := range mailboxes {
 51→		bounceStats, err := mailboxBounceStats(d, mailbox.ID, now, 14)
 52→		if err != nil {
 53→			return nil, err
 54→		}
 55→
 56→		health := MailboxHealth{
 57→			Mailbox:                mailbox,
 58→			WarmupDay:              warmupDay(mailbox.Mailbox, now),
 59→			EffectiveFirstTouchCap: mailbox.FirstTouchDailyCap,
 60→			EffectiveFollowUpCap:   mailbox.FollowUpDailyCap,
 61→			EffectiveReplyCap:      mailbox.ReplyDailyCap,
 62→			BounceStats:            bounceStats,
 63→		}
 64→
 65→		if withDNS {
 66→			auth := lookupDomainAuth(domainFromEmail(mailbox.Email))
 67→			health.DomainAuth = &auth
 68→		}
 69→
 70→		health.HealthScore = calculateHealthScore(health)
 71→		health.Risk = healthRisk(health.HealthScore)
 72→		items = append(items, health)
 73→	}
 74→
 75→	return items, nil
 76→}
