 78→func mailboxBounceStats(d *sql.DB, mailboxID string, now time.Time, windowDays int) (BounceStats, error) {
 79→	if windowDays <= 0 {
 80→		windowDays = 14
 81→	}
 82→	stats := BounceStats{WindowDays: windowDays}
 83→
 84→	start := now.AddDate(0, 0, -windowDays).Format("2006-01-02")
 85→	if err := d.QueryRow(`
 86→		SELECT COALESCE(SUM(first_touches_sent + follow_ups_sent + replies_sent), 0)
 87→		FROM mailbox_daily_usage
 88→		WHERE mailbox_id = ? AND usage_day >= ?`,
 89→		mailboxID, start,
 90→	).Scan(&stats.Sends); err != nil {
 91→		return stats, err
 92→	}
 93→
 94→	if err := d.QueryRow(`
 95→		SELECT COUNT(*)
 96→		FROM reply_events
 97→		WHERE mailbox_id = ? AND classification = 'bounced' AND occurred_at >= ?`,
 98→		mailboxID, now.AddDate(0, 0, -windowDays).UTC().Format(time.RFC3339),
 99→	).Scan(&stats.Bounces); err != nil {
100→		return stats, err
101→	}
102→
103→	if stats.Sends > 0 {
104→		stats.BounceRate = float64(stats.Bounces) / float64(stats.Sends)
105→	}
106→
107→	return stats, nil
108→}
109→
110→func lookupDomainAuth(domain string) DomainAuthStatus {
111→	status := DomainAuthStatus{
112→		Domain:     domain,
113→		DKIMStatus: "unknown (selector-specific)",
114→	}
115→	if domain == "" {
116→		status.LookupError = "mailbox domain missing"
117→		return status
118→	}
119→
120→	if mx, err := net.LookupMX(domain); err == nil && len(mx) > 0 {
121→		status.MXPresent = true
122→	}
123→	txts, err := net.LookupTXT(domain)
124→	if err == nil {
125→		for _, txt := range txts {
126→			if strings.Contains(strings.ToLower(txt), "v=spf1") {
127→				status.SPFPresent = true
128→				break
129→			}
130→		}
131→	} else if status.LookupError == "" {
132→		status.LookupError = err.Error()
133→	}
134→
135→	dmarcTXT, err := net.LookupTXT("_dmarc." + domain)
136→	if err == nil {
137→		for _, txt := range dmarcTXT {
138→			if strings.Contains(strings.ToLower(txt), "v=dmarc1") {
139→				status.DMARCPresent = true
140→				break
141→			}
142→		}
143→	} else if status.LookupError == "" {
144→		status.LookupError = err.Error()
145→	}
146→
147→	return status
148→}
149→
150→func calculateHealthScore(health MailboxHealth) int {
151→	score := health.Mailbox.ReputationScore
152→	if score == 0 {
153→		score = 100
154→	}
155→
156→	switch {
157→	case health.BounceStats.BounceRate >= 0.12:
158→		score -= 35
159→	case health.BounceStats.BounceRate >= 0.08:
160→		score -= 20
161→	case health.BounceStats.Bounces > 0:
162→		score -= 10
163→	}
164→
165→	if health.Mailbox.Status != "active" {
166→		score -= 20
167→	}
168→
169→	if health.DomainAuth != nil {
170→		if !health.DomainAuth.MXPresent {
171→			score -= 10
172→		}
173→		if !health.DomainAuth.SPFPresent {
174→			score -= 10
175→		}
176→		if !health.DomainAuth.DMARCPresent {
177→			score -= 10
178→		}
179→	}
180→
181→	if health.Mailbox.LastBounceAt != "" {
182→		if bouncedAt := parseOptionalTime(health.Mailbox.LastBounceAt); !bouncedAt.IsZero() && time.Since(bouncedAt) < 14*24*time.Hour {
183→			score -= 10
184→		}
185→	}
186→
187→	if score < 0 {
188→		return 0
189→	}
190→	if score > 100 {
191→		return 100
192→	}
193→	return score
194→}
195→
196→func healthRisk(score int) string {
197→	switch {
198→	case score >= 85:
199→		return "healthy"
200→	case score >= 65:
201→		return "watch"
202→	default:
203→		return "at-risk"
204→	}
205→}
206→
207→func warmupDay(mailbox Mailbox, now time.Time) int {
208→	startedAt := parseOptionalTime(mailbox.WarmupStartedAt)
209→	if startedAt.IsZero() {
210→		return 0
211→	}
212→	if now.UTC().Before(startedAt.UTC()) {
213→		return 0
214→	}
215→	return int(now.UTC().Sub(startedAt.UTC()).Hours() / 24)
216→}
