218→func maybeAutoSuppressDomainForBounces(tx *sql.Tx, contactEmail, reason string, occurredAt time.Time) error {
219→	domain := domainFromEmail(contactEmail)
220→	if domain == "" {
221→		return nil
222→	}
223→
224→	var bounceCount int
225→	if err := tx.QueryRow(`
226→		SELECT COUNT(*)
227→		FROM reply_events
228→		WHERE classification = 'bounced'
229→			AND lower(contact_email) LIKE ?
230→			AND occurred_at >= ?`,
231→		"%@"+domain,
232→		occurredAt.AddDate(0, 0, -30).UTC().Format(time.RFC3339),
233→	).Scan(&bounceCount); err != nil {
234→		return err
235→	}
236→	if bounceCount < 2 {
237→		return nil
238→	}
239→
240→	_, err := tx.Exec(`
241→		INSERT INTO suppressions (id, scope, value, reason, source)
242→		VALUES (?, 'domain', ?, ?, 'bounce')
243→		ON CONFLICT(scope, value) DO UPDATE SET reason = excluded.reason, source = excluded.source`,
244→		newID("sup"), domain, fmt.Sprintf("%s:domain", reason),
245→	)
246→	return err
247→}
