  9→// Options holds CLI flags for nurge init.
 10→type Options struct {
 11→	SkipHooks bool
 12→	Force     bool
 13→	Verbose   bool
 14→}
 15→
 16→// Step is the interface each init step implements.
 17→type Step interface {
 18→	Name() string
 19→	Done() (bool, error)
 20→	Run() error
 21→}
 22→
 23→// Run executes all init steps in order.
 24→func Run(opts Options) error {
 25→	fmt.Println()
 26→	fmt.Println("  nurge — outbound that learns")
 27→	fmt.Println()
 28→
 29→	steps := buildSteps(opts)
 30→
 31→	for _, s := range steps {
 32→		if !opts.Force {
 33→			done, err := s.Done()
 34→			if err != nil {
 35→				printFail(s.Name(), err)
 36→				return err
 37→			}
 38→			if done {
 39→				printSkip(s.Name())
 40→				continue
 41→			}
 42→		}
 43→
 44→		if err := s.Run(); err != nil {
 45→			printFail(s.Name(), err)
 46→			return err
 47→		}
 48→		printDone(s.Name())
 49→	}
 50→
 51→	return nil
 52→}
 53→
 54→func buildSteps(opts Options) []Step {
 55→	var steps []Step
 56→
 57→	steps = append(steps, &projectStep{})
 58→	steps = append(steps, &databaseStep{})
 59→	steps = append(steps, &gitignoreStep{})
 60→
 61→	if !opts.SkipHooks {
 62→		steps = append(steps, &hooksStep{})
 63→	}
 64→
 65→	steps = append(steps, &skillStep{})
 66→	steps = append(steps, &gitStep{})
 67→	steps = append(steps, &nextStepStep{})
 68→
 69→	return steps
 70→}
 71→
 72→func printDone(name string) {
 73→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s\n", name)
 74→}
 75→
 76→func printSkip(name string) {
 77→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s (already done)\n", name)
 78→}
 79→
 80→func printFail(name string, err error) {
 81→	fmt.Fprintf(os.Stderr, "  \033[31m✗\033[0m %s: %v\n", name, err)
 82→}
