 84→// IsDirEmpty returns true if dir contains no entries except allowed ones
 85→// (.nurge, .git, .gitignore, .DS_Store, .claude).
 86→func IsDirEmpty(dir string) (bool, error) {
 87→	allowed := map[string]bool{
 88→		".nurge":     true,
 89→		".git":       true,
 90→		".gitignore": true,
 91→		".DS_Store":  true,
 92→		".claude":    true,
 93→	}
 94→
 95→	entries, err := os.ReadDir(dir)
 96→	if err != nil {
 97→		return false, err
 98→	}
 99→	for _, e := range entries {
100→		name := strings.TrimSuffix(e.Name(), "/")
101→		if !allowed[name] {
102→			return false, nil
103→		}
104→	}
105→	return true, nil
106→}
107→
108→// IsNurgeProject returns true if dir contains a .nurge/ directory.
109→func IsNurgeProject(dir string) bool {
110→	info, err := os.Stat(filepath.Join(dir, ".nurge"))
111→	return err == nil && info.IsDir()
112→}
