 76→// CurrentSnapshotCounts returns the current email + learning counts used as
 77→// the basis for skill version metadata.
 78→func CurrentSnapshotCounts(db *sql.DB) (*SnapshotCounts, error) {
 79→	counts := &SnapshotCounts{}
 80→	if err := db.QueryRow(`SELECT COUNT(*) FROM emails`).Scan(&counts.EmailCount); err != nil {
 81→		return nil, fmt.Errorf("counting emails: %w", err)
 82→	}
 83→	if err := db.QueryRow(`SELECT COUNT(*) FROM learnings`).Scan(&counts.LearningCount); err != nil {
