 89→// SaveStrategicMemory inserts or updates a distilled execution insight.
 90→func SaveStrategicMemory(db *sql.DB, input StrategicMemoryInput) error {
 91→	if strings.TrimSpace(input.Category) == "" {
 92→		return fmt.Errorf("strategic memory category is required")
 93→	}
 94→	if strings.TrimSpace(input.Summary) == "" {
 95→		return fmt.Errorf("strategic memory summary is required")
 96→	}
 97→	if strings.TrimSpace(input.SourceKey) == "" {
 98→		return fmt.Errorf("strategic memory source key is required")
 99→	}
100→
101→	affectedSkillsJSON, err := json.Marshal(uniqueSortedStrings(input.AffectedSkills))
102→	if err != nil {
103→		return fmt.Errorf("marshaling affected skills: %w", err)
104→	}
105→	evidenceJSON := []byte("{}")
106→	if len(input.Evidence) > 0 {
107→		evidenceJSON, err = json.Marshal(input.Evidence)
108→		if err != nil {
109→			return fmt.Errorf("marshaling evidence: %w", err)
110→		}
111→	}
112→	source := strings.TrimSpace(input.Source)
113→	if source == "" {
114→		source = "execution_sync"
115→	}
116→
117→	_, err = db.Exec(`
118→		INSERT INTO strategic_memory (
119→			category,
120→			summary,
121→			affected_skills,
122→			evidence,
123→			source,
124→			source_key,
125→			priority
126→		) VALUES (?, ?, ?, ?, ?, ?, ?)
127→		ON CONFLICT(source_key) DO UPDATE SET
128→			summary = excluded.summary,
129→			affected_skills = excluded.affected_skills,
130→			evidence = excluded.evidence,
131→			priority = excluded.priority,
132→			last_seen_at = datetime('now'),
133→			occurrence_count = strategic_memory.occurrence_count + 1,
134→			updated_at = datetime('now')`,
135→		input.Category,
136→		input.Summary,
137→		string(affectedSkillsJSON),
138→		string(evidenceJSON),
139→		source,
140→		input.SourceKey,
141→		input.Priority,
142→	)
143→	if err != nil {
144→		return fmt.Errorf("saving strategic memory: %w", err)
145→	}
146→	return nil
147→}
