120→		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
121→			fmt.Printf("Enter your %s API key: ", g.def.Name)
122→			fmt.Scanln(&key)
123→		}
124→		if key == "" {
125→			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
126→		}
127→	}
128→
129→	// Save API key
130→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
131→	if err := os.MkdirAll(tokenDir, 0755); err != nil {
132→		return nil, fmt.Errorf("creating connector dir: %w", err)
133→	}
