348→// saveSyncState persists the sync cursor.
349→func (e *Engine) saveSyncState(state *SyncState) error {
350→	data, err := json.Marshal(state)
351→	if err != nil {
352→		return err
353→	}
354→
355→	_, err = e.db.Exec(`
356→		INSERT INTO connectors (id, type, sync_cursor)
357→		VALUES (?, 'sync', ?)
358→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
359→		syncStateKey, string(data),
360→	)
361→	return err
362→}
