277→func recipientsJSON(raw string) string {
278→	raw = strings.TrimSpace(raw)
279→	if raw == "" {
280→		return "[]"
281→	}
282→	parts := strings.Split(raw, ",")
283→	recipients := make([]string, 0, len(parts))
284→	for _, part := range parts {
285→		part = strings.TrimSpace(part)
286→		if part != "" {
287→			recipients = append(recipients, part)
288→		}
289→	}
290→	data, _ := json.Marshal(recipients)
291→	return string(data)
292→}
