132→// Push sends local state changes to Convex.
133→func (e *Engine) Push() (*PushResult, error) {
134→	state, err := e.loadSyncState()
135→	if err != nil {
136→		return nil, fmt.Errorf("loading sync state: %w", err)
137→	}
138→
139→	result := &PushResult{}
140→	var allRows []account.SyncRow
141→
142→	for _, table := range localTables {
143→		rows, err := e.changedLocalRows(table, state.LastPushAt)
144→		if err != nil {
145→			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
146→		}
147→		allRows = append(allRows, rows...)
148→		result.TablesScanned++
149→	}
150→
151→	// Also push email classifications (local authority for the classification field)
152→	classRows, err := e.changedEmailClassifications()
153→	if err != nil {
154→		return nil, fmt.Errorf("reading changed email classifications: %w", err)
155→	}
156→	allRows = append(allRows, classRows...)
157→
158→	if len(allRows) == 0 {
159→		return result, nil
160→	}
161→
162→	// Push in batches
163→	for i := 0; i < len(allRows); i += batchSize {
164→		end := i + batchSize
165→		if end > len(allRows) {
166→			end = len(allRows)
167→		}
168→		batch := allRows[i:end]
169→
170→		resp, err := e.client.PushLocalState(e.token, batch)
171→		if err != nil {
172→			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
173→		}
174→
175→		// Update local sync_version from server response
176→		for id, version := range resp.Versions {
177→			for _, row := range batch {
178→				if row.ID == id {
179→					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
180→						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
181→					}
182→					break
183→				}
184→			}
185→		}
186→		result.RowsPushed += len(batch)
187→	}
188→
189→	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
190→	if err := e.saveSyncState(state); err != nil {
191→		return nil, fmt.Errorf("saving sync state: %w", err)
192→	}
193→
194→	return result, nil
195→}
