 11→const BATCH_SIZE = 10;
 12→
 13→// Cron entry point: find due tasks, validate, dispatch sends
 14→export const checkDueTasks = internalAction({
 15→  handler: async (ctx) => {
 16→    const now = new Date().toISOString();
 17→
 18→    const dueTasks = await ctx.runQuery(internal.dispatcher.findDueTasks, {
 19→      now,
 20→      limit: BATCH_SIZE,
 21→    });
 22→
 23→    if (dueTasks.length === 0) return;
 24→
 25→    for (const task of dueTasks) {
 26→      try {
 27→        const enrollment = await ctx.runQuery(
 28→          internal.dispatcher.getEnrollment,
 29→          { enrollmentId: task.enrollmentId }
 30→        );
 31→        if (!enrollment || enrollment.status !== "active") continue;
 32→
 33→        const suppression = await ctx.runQuery(
 34→          internal.dispatcher.checkSuppression,
 35→          { userId: task.userId, email: task.contactEmail }
 36→        );
 37→        if (suppression.suppressed) {
 38→          await ctx.runMutation(internal.dispatcher.cancelTask, {
 39→            taskId: task.externalId,
 40→            userId: task.userId,
 41→            reason: `Contact suppressed: ${suppression.reason}`,
 42→          });
 43→          continue;
 44→        }
 45→
 46→        const mailbox = await ctx.runQuery(
 47→          internal.dispatcher.getMailbox,
 48→          { mailboxId: task.mailboxId }
 49→        );
 50→        if (!mailbox || mailbox.status !== "active") continue;
 51→        if (
 52→          !withinSendWindow(
 53→            mailbox.sendWindowStartHour,
 54→            mailbox.sendWindowEndHour,
 55→            mailbox.sendWindowTimezone
 56→          )
 57→        ) {
 58→          continue;
 59→        }
 60→
 61→        const today = todayInTimezone(mailbox.sendWindowTimezone);
 62→        const sendCount = await ctx.runQuery(
 63→          internal.dispatcher.countSends,
 64→          { mailboxId: task.mailboxId, sendType: task.sendType, day: today }
 65→        );
 66→
 67→        const capMap: Record<string, number> = {
 68→          first_touch: mailbox.firstTouchDailyCap,
 69→          follow_up: mailbox.followUpDailyCap,
 70→          reply: mailbox.replyDailyCap,
 71→        };
 72→        const cap = capMap[task.sendType] || 0;
 73→        if (cap > 0 && sendCount >= cap) continue;
 74→
 75→        const draft = await ctx.runQuery(
 76→          internal.dispatcher.getDraft,
 77→          { taskId: task.externalId }
 78→        );
 79→        if (draft && draft.status === "stale") continue;
 80→
 81→        await ctx.runMutation(internal.dispatcher.claimTask, {
 82→          taskId: task.externalId,
 83→          userId: task.userId,
 84→        });
 85→
 86→        const unipileAccount = await ctx.runQuery(
 87→          internal.dispatcher.getUnipileAccount,
 88→          { userId: task.userId, provider: "GOOGLE" }
 89→        );
 90→        if (!unipileAccount) continue;
 91→
 92→        const subject = draft?.subject || task.subject || "";
 93→        const body = draft?.body || task.body || "";
 94→
 95→        await ctx.runAction(internal.send.sendViaUnipile, {
 96→          userId: task.userId,
 97→          taskId: task.externalId,
 98→          accountId: unipileAccount.unipileAccountId,
 99→          to: task.contactEmail,
100→          subject,
101→          body,
102→          replyTo: enrollment.unipileThreadProviderId || undefined,
103→        });
104→      } catch (error) {
105→        console.error(`Error processing task ${task.externalId}:`, error);
106→      }
107→    }
108→  },
109→});
