  1→import { v } from "convex/values";
  2→import { internalAction, internalMutation } from "./_generated/server";
  3→import { internal } from "./_generated/api";
  4→
  5→// Send via Unipile — called by cron or by CLI send intent
  6→export const sendViaUnipile = internalAction({
  7→  args: {
  8→    userId: v.string(),
  9→    taskId: v.string(), // externalId of follow_up_task
 10→    accountId: v.string(), // Unipile account ID
 11→    to: v.string(),
 12→    subject: v.string(),
 13→    body: v.string(),
 14→    replyTo: v.optional(v.string()), // provider_id for threading
 15→  },
 16→  handler: async (ctx, args) => {
 17→    const apiKey = process.env.UNIPILE_API_KEY;
 18→    const apiUrl = process.env.UNIPILE_API_URL;
 19→    if (!apiKey || !apiUrl) {
 20→      // Record failure
 21→      await ctx.runMutation(internal.send.recordSendFailure, {
 22→        userId: args.userId,
 23→        taskId: args.taskId,
 24→        error: "Unipile API key or URL not configured",
 25→      });
 26→      return { ok: false, error: "Unipile not configured" };
 27→    }
 28→
 29→    try {
 30→      const payload: Record<string, any> = {
 31→        account_id: args.accountId,
 32→        to: [{ identifier: args.to }],
 33→        subject: args.subject,
 34→        body: args.body,
 35→      };
 36→
 37→      if (args.replyTo) {
 38→        payload.reply_to = args.replyTo;
 39→      }
 40→
 41→      const resp = await fetch(`${apiUrl}/api/v1/emails`, {
 42→        method: "POST",
 43→        headers: {
 44→          "X-API-KEY": apiKey,
 45→          "Content-Type": "application/json",
 46→        },
 47→        body: JSON.stringify(payload),
 48→      });
 49→
 50→      if (!resp.ok) {
 51→        const errorText = await resp.text();
 52→
 53→        // Check for auth errors
 54→        if (resp.status === 401 || resp.status === 403) {
 55→          await ctx.runMutation(internal.send.recordAuthFailure, {
 56→            userId: args.userId,
 57→            taskId: args.taskId,
 58→            mailboxId: "", // will be resolved in mutation
 59→            error: `Auth error: ${errorText}`,
 60→          });
 61→          return { ok: false, error: `Auth error: ${resp.status}` };
 62→        }
 63→
 64→        await ctx.runMutation(internal.send.recordSendFailure, {
 65→          userId: args.userId,
 66→          taskId: args.taskId,
 67→          error: `Unipile API error ${resp.status}: ${errorText}`,
 68→        });
 69→        return { ok: false, error: errorText };
 70→      }
 71→
 72→      const result = await resp.json();
 73→
 74→      // Record success
 75→      await ctx.runMutation(internal.send.recordSendSuccess, {
 76→        userId: args.userId,
 77→        taskId: args.taskId,
 78→        unipileMessageId: result.id || "",
 79→        providerId: JSON.stringify(result.provider_id || ""),
 80→      });
 81→
 82→      return { ok: true, messageId: result.id, providerId: result.provider_id };
 83→    } catch (error: any) {
 84→      await ctx.runMutation(internal.send.recordSendFailure, {
 85→        userId: args.userId,
 86→        taskId: args.taskId,
 87→        error: error.message || "Unknown error",
 88→      });
 89→      return { ok: false, error: error.message };
 90→    }
 91→  },
 92→});
 93→
 94→// Record successful send — updates task, creates send event, advances enrollment
 95→export const recordSendSuccess = internalMutation({
 96→  args: {
 97→    userId: v.string(),
 98→    taskId: v.string(),
 99→    unipileMessageId: v.string(),
100→    providerId: v.string(),
101→  },
102→  handler: async (ctx, args) => {
103→    const task = await ctx.db
104→      .query("followUpTasks")
105→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
106→      .first();
107→
108→    if (!task) return;
109→
110→    const syncState = await ctx.db
111→      .query("syncState")
112→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
113→      .first();
114→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
115→
116→    // Update task
117→    await ctx.db.patch(task._id, {
118→      status: "completed",
119→      sendStatus: "sent",
120→      completedAt: new Date().toISOString(),
121→      unipileMessageId: args.unipileMessageId,
122→      providerId: args.providerId,
123→      syncVersion: version,
124→    });
125→
126→    // Create send event
127→    const sendEventId = `mse-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
128→    await ctx.db.insert("mailboxSendEvents", {
129→      externalId: sendEventId,
130→      mailboxId: task.mailboxId,
131→      sendType: task.sendType,
132→      sentAt: new Date().toISOString(),
133→      taskId: args.taskId,
134→      enrollmentId: task.enrollmentId,
135→      unipileMessageId: args.unipileMessageId,
136→      providerId: args.providerId,
137→      syncVersion: version,
138→      userId: args.userId,
139→    });
140→
141→    // Advance enrollment
142→    const enrollment = await ctx.db
143→      .query("sequenceEnrollments")
144→      .withIndex("by_external_id", (q) => q.eq("externalId", task.enrollmentId))
145→      .first();
146→
147→    if (enrollment) {
148→      version++;
149→      const newStep = task.stepNumber;
150→      const isComplete = newStep >= enrollment.totalSteps;
151→
152→      await ctx.db.patch(enrollment._id, {
153→        currentStep: newStep,
154→        lastSentAt: new Date().toISOString(),
155→        lastMessageId: args.unipileMessageId,
156→        status: isComplete ? "completed" : enrollment.status,
157→        nextDueAt: isComplete ? "" : enrollment.nextDueAt,
158→        unipileThreadProviderId: args.providerId || enrollment.unipileThreadProviderId,
159→        syncVersion: version,
160→      });
161→
162→      // Mark draft as sent
163→      const draft = await ctx.db
164→        .query("sequenceDrafts")
165→        .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
166→        .first();
167→      if (draft) {
168→        await ctx.db.patch(draft._id, {
169→          status: "sent",
170→          syncVersion: version,
171→        });
172→      }
173→    }
174→
175→    // Update sync state
176→    if (syncState) {
177→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
178→    } else {
179→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
180→    }
181→  },
182→});
183→
184→// Record send failure — increment attempt count, set error
185→export const recordSendFailure = internalMutation({
186→  args: {
187→    userId: v.string(),
188→    taskId: v.string(),
189→    error: v.string(),
190→  },
191→  handler: async (ctx, args) => {
192→    const task = await ctx.db
193→      .query("followUpTasks")
194→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
195→      .first();
196→
197→    if (!task) return;
198→
199→    const syncState = await ctx.db
200→      .query("syncState")
201→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
202→      .first();
203→    const version = (syncState?.lastSyncVersion ?? 0) + 1;
204→
205→    const newAttemptCount = task.attemptCount + 1;
206→    const maxRetries = 5;
207→
208→    // Check stale window (48 hours past due)
209→    const dueAt = new Date(task.dueAt).getTime();
210→    const now = Date.now();
211→    const staleWindowMs = 48 * 60 * 60 * 1000;
212→    const isStale = now - dueAt > staleWindowMs;
213→
214→    const isFailed = newAttemptCount >= maxRetries || isStale;
215→
216→    await ctx.db.patch(task._id, {
217→      sendStatus: isFailed ? "failed" : "pending", // back to pending for retry
218→      lastAttemptAt: new Date().toISOString(),
219→      lastError: args.error,
220→      attemptCount: newAttemptCount,
221→      status: isFailed ? "canceled" : task.status,
222→      canceledReason: isFailed
223→        ? isStale
224→          ? "stale: past 48h window"
225→          : `max retries (${maxRetries}) exceeded`
226→        : task.canceledReason,
227→      syncVersion: version,
228→    });
229→
230→    if (syncState) {
231→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
232→    } else {
233→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
234→    }
235→  },
236→});
237→
238→// Record auth failure — mark mailbox as auth_expired, pause enrollment
239→export const recordAuthFailure = internalMutation({
240→  args: {
241→    userId: v.string(),
242→    taskId: v.string(),
243→    mailboxId: v.string(),
244→    error: v.string(),
245→  },
246→  handler: async (ctx, args) => {
247→    const task = await ctx.db
248→      .query("followUpTasks")
249→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
250→      .first();
251→
252→    if (!task) return;
253→
254→    const syncState = await ctx.db
255→      .query("syncState")
256→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
257→      .first();
258→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
259→
260→    // Mark task as failed (don't retry auth errors)
261→    await ctx.db.patch(task._id, {
262→      sendStatus: "failed",
263→      lastError: args.error,
264→      lastAttemptAt: new Date().toISOString(),
265→      syncVersion: version,
266→    });
267→
268→    // Mark mailbox as auth_expired
269→    const mailbox = await ctx.db
270→      .query("mailboxes")
271→      .withIndex("by_external_id", (q) => q.eq("externalId", task.mailboxId))
272→      .first();
273→
274→    if (mailbox) {
275→      version++;
276→      await ctx.db.patch(mailbox._id, {
277→        status: "auth_expired",
278→        syncVersion: version,
279→      });
280→    }
281→
282→    if (syncState) {
283→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
284→    } else {
285→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
286→    }
287→  },
288→});
