func BuiltInTemplates() []Template {
	names := make([]string, 0, len(builtInTemplates))
	for name := range builtInTemplates {
		names = append(names, name)
	}
	sort.Strings(names)

	templates := make([]Template, 0, len(names))
	for _, name := range names {
		templates = append(templates, builtInTemplates[name])
	}
	return templates
}

func NormalizeSendType(sendType string) string {
	switch sendType {
	case SendTypeFirstTouch, SendTypeFollowUp, SendTypeReply, SendTypeManual:
		return sendType
	default:
		return SendTypeManual
	}
}

func EnsureMailbox(d *sql.DB, email, provider string) (*Mailbox, error) {
	if email == "" {
		return nil, fmt.Errorf("mailbox email is required")
	}

	_, err := d.Exec(`
		INSERT INTO mailboxes (id, email, transport_email, provider, warmup_started_at)
		VALUES (?, ?, ?, ?, datetime('now'))
		ON CONFLICT(email) DO UPDATE SET
			provider = excluded.provider,
			transport_email = CASE
				WHEN mailboxes.transport_email = '' THEN excluded.transport_email
				ELSE mailboxes.transport_email
			END,
			warmup_started_at = CASE
				WHEN mailboxes.warmup_started_at = '' THEN excluded.warmup_started_at
				ELSE mailboxes.warmup_started_at
			END,
			updated_at = datetime('now')`,
		newID("mbx"), email, email, provider,
	)
	if err != nil {
		return nil, err
	}

	return mailboxByEmail(d, email)
}

func ListMailboxes(d *sql.DB, now time.Time) ([]MailboxStatus, error) {
	if now.IsZero() {
		now = time.Now()
	}

	rows, err := d.Query(`
		SELECT
			m.id, m.email, m.transport_email, m.rotation_group, m.provider, m.status, m.warmup_stage, m.warmup_started_at,
			m.first_touch_daily_cap, m.follow_up_daily_cap, m.reply_daily_cap, m.min_gap_minutes,
			m.send_window_start_hour, m.send_window_end_hour, m.send_window_timezone,
			m.reputation_score, m.priority, m.last_used_at, m.last_bounce_at,
			COALESCE(u.first_touches_sent, 0),
			COALESCE(u.follow_ups_sent, 0),
			COALESCE(u.replies_sent, 0)
		FROM mailboxes m
		LEFT JOIN mailbox_daily_usage u
			ON u.mailbox_id = m.id AND u.usage_day = ?
		ORDER BY m.email ASC`,
		dayKey(now),
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var result []MailboxStatus
	for rows.Next() {
		var m MailboxStatus
		m.UsageDay = dayKey(now)
		if err := rows.Scan(
			&m.ID, &m.Email, &m.TransportEmail, &m.RotationGroup, &m.Provider, &m.Status, &m.WarmupStage, &m.WarmupStartedAt,
			&m.FirstTouchDailyCap, &m.FollowUpDailyCap, &m.ReplyDailyCap, &m.MinGapMinutes,
			&m.SendWindowStartHour, &m.SendWindowEndHour, &m.SendWindowTimezone,
			&m.ReputationScore, &m.Priority, &m.LastUsedAt, &m.LastBounceAt,
			&m.FirstTouchesSent, &m.FollowUpsSent, &m.RepliesSent,
		); err != nil {
			return nil, err
		}
		m.FirstTouchDailyCap, m.FollowUpDailyCap, m.ReplyDailyCap = effectiveCaps(m.Mailbox, now)
		m.FirstTouchesRemaining = remaining(m.FirstTouchDailyCap, m.FirstTouchesSent)
		m.FollowUpsRemaining = remaining(m.FollowUpDailyCap, m.FollowUpsSent)
		m.RepliesRemaining = remaining(m.ReplyDailyCap, m.RepliesSent)
		result = append(result, m)
	}

	return result, rows.Err()
}

func CanSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
	sendType = NormalizeSendType(sendType)
	if sendType == SendTypeManual {
		return nil
	}
	if now.IsZero() {
		now = time.Now()
	}

	mailbox, usage, err := mailboxAndUsage(d, mailboxID, now)
	if err != nil {
		return err
	}
	if mailbox.Status != "active" {
		return fmt.Errorf("mailbox %s is %s", mailbox.Email, mailbox.Status)
	}
	if mailbox.ReputationScore > 0 && mailbox.ReputationScore < 40 {
		return fmt.Errorf("mailbox %s reputation is too low (%d)", mailbox.Email, mailbox.ReputationScore)
	}
	if !withinSendWindow(*mailbox, now) {
		return fmt.Errorf("mailbox %s is outside its send window (%s %02d:00-%02d:00)", mailbox.Email, mailbox.SendWindowTimezone, mailbox.SendWindowStartHour, mailbox.SendWindowEndHour)
	}
	if mailbox.LastBounceAt != "" && sendType == SendTypeFirstTouch {
		if bouncedAt, err := time.Parse(time.RFC3339, mailbox.LastBounceAt); err == nil && now.UTC().Before(bouncedAt.Add(24*time.Hour)) {
			return fmt.Errorf("mailbox %s is cooling off after a recent bounce until %s", mailbox.Email, bouncedAt.Add(24*time.Hour).Format(time.RFC3339))
		}
	}
	if bounceStats, err := mailboxBounceStats(d, mailboxID, now, 14); err == nil {
		switch {
		case bounceStats.Sends >= 10 && bounceStats.BounceRate >= 0.12:
			return fmt.Errorf("mailbox %s bounce rate is too high (%.1f%% over %d sends in %dd)", mailbox.Email, bounceStats.BounceRate*100, bounceStats.Sends, bounceStats.WindowDays)
		case sendType == SendTypeFirstTouch && bounceStats.Sends >= 10 && bounceStats.BounceRate >= 0.08:
			return fmt.Errorf("mailbox %s first touches are paused because bounce rate reached %.1f%% over the last %d days", mailbox.Email, bounceStats.BounceRate*100, bounceStats.WindowDays)
		}
	} else {
		return err
	}

	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox, now)

	switch sendType {
	case SendTypeFirstTouch:
		if firstTouchCap > 0 && usage.FirstTouchesSent >= firstTouchCap {
			return fmt.Errorf("mailbox %s has reached its first-touch daily cap (%d/%d)", mailbox.Email, usage.FirstTouchesSent, firstTouchCap)
		}
	case SendTypeFollowUp:
		if followUpCap > 0 && usage.FollowUpsSent >= followUpCap {
			return fmt.Errorf("mailbox %s has reached its follow-up daily cap (%d/%d)", mailbox.Email, usage.FollowUpsSent, followUpCap)
		}
	case SendTypeReply:
		if replyCap > 0 && usage.RepliesSent >= replyCap {
			return fmt.Errorf("mailbox %s has reached its reply daily cap (%d/%d)", mailbox.Email, usage.RepliesSent, replyCap)
		}
	}

	if mailbox.MinGapMinutes > 0 {
		lastSentAt, err := latestMailboxOutboundAt(d, effectiveTransportEmail(*mailbox))
		if err != nil {
			return err
		}
		if !lastSentAt.IsZero() {
			nextAllowed := lastSentAt.Add(time.Duration(mailbox.MinGapMinutes) * time.Minute)
			if now.UTC().Before(nextAllowed) {
				return fmt.Errorf("mailbox %s is cooling down until %s", mailbox.Email, nextAllowed.Format(time.RFC3339))
			}
		}
	}

	return nil
}

func CreateEnrollmentAfterFirstTouch(d *sql.DB, opts EnrollmentOptions) (*Enrollment, *Task, error) {
	if opts.MailboxID == "" {
		return nil, nil, fmt.Errorf("mailbox ID is required")
	}
	if opts.ContactEmail == "" {
		return nil, nil, fmt.Errorf("contact email is required")
	}
	if opts.SentAt.IsZero() {
		opts.SentAt = time.Now()
	}
	if existing, err := ActiveEnrollmentForContact(d, opts.MailboxID, opts.ContactEmail); err != nil {
		return nil, nil, err
	} else if existing != nil {
		return nil, nil, fmt.Errorf("%s already has an active sequence enrollment (%s)", opts.ContactEmail, existing.ID)
	}

	template, err := TemplateByName(d, opts.SequenceName)
	if err != nil {
		return nil, nil, err
	}

	tx, err := d.Begin()
	if err != nil {
		return nil, nil, err
	}
	defer tx.Rollback()

	enrollmentID := newID("seq")
	nextDue := ""
	var nextTask *Task
	if len(template.Steps) > 1 {
		nextDelay, err := stepDelay(template.Steps[1])
		if err != nil {
			return nil, nil, err
		}
		nextDueAt := opts.SentAt.Add(nextDelay).UTC()
		nextSubject, nextBody := renderStep(template.Steps[1], Enrollment{
			SequenceName: template.Name,
			CampaignName: defaultCampaignName(opts),
			MailboxID:    opts.MailboxID,
			ContactEmail: opts.ContactEmail,
			ContactName:  opts.ContactName,
			Subject:      opts.Subject,
			ThreadID:     opts.ThreadID,
			InitialBody:  opts.InitialBody,
		})
		nextDue = nextDueAt.Format(time.RFC3339)
		nextTask = &Task{
			ID:           newID("task"),
			EnrollmentID: enrollmentID,
			MailboxID:    opts.MailboxID,
			ContactEmail: opts.ContactEmail,
			Subject:      nextSubject,
			Body:         nextBody,
			ThreadID:     opts.ThreadID,
			StepNumber:   template.Steps[1].StepNumber,
			StepName:     template.Steps[1].Name,
			SendType:     template.Steps[1].SendType,
			Status:       TaskStatusOpen,
			DueAt:        nextDueAt.Format(time.RFC3339),
			SequenceName: template.Name,
		}
	}

	_, err = tx.Exec(`
		INSERT INTO sequence_enrollments (
			id, sequence_name, campaign_name, mailbox_id, contact_email, contact_name, subject,
			thread_id, last_message_id, status, status_reason, reply_state, current_step, total_steps, last_sent_at, last_reply_at, next_due_at, initial_body
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		enrollmentID, template.Name, defaultCampaignName(opts), opts.MailboxID, opts.ContactEmail, opts.ContactName,
		opts.Subject, opts.ThreadID, opts.MessageID, StatusActive, "", "", 1, len(template.Steps),
		opts.SentAt.UTC().Format(time.RFC3339), "", nextDue, opts.InitialBody,
	)
	if err != nil {
		return nil, nil, err
	}

	if nextTask != nil {
		_, err = tx.Exec(`
			INSERT INTO follow_up_tasks (
				id, enrollment_id, mailbox_id, contact_email, subject, body, thread_id,
				step_number, step_name, send_type, status, send_status, due_at
			) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
			nextTask.ID, nextTask.EnrollmentID, nextTask.MailboxID, nextTask.ContactEmail,
			nextTask.Subject, nextTask.Body, nextTask.ThreadID, nextTask.StepNumber, nextTask.StepName,
			nextTask.SendType, nextTask.Status, TaskSendStatusPending, nextTask.DueAt,
		)
		if err != nil {
			return nil, nil, err
		}
		if err := UpsertDraftForTask(tx, nextTask.ID, nextTask.EnrollmentID, nextTask.StepNumber, nextTask.Subject, nextTask.Body, "sequence-runtime", "initial enrollment"); err != nil {
			return nil, nil, err
		}
	}

	if err := tx.Commit(); err != nil {
		return nil, nil, err
	}

	enrollment, err := EnrollmentByID(d, enrollmentID)
	if err != nil {
		return nil, nil, err
	}

	if nextTask != nil {
		nextTask, err = TaskByID(d, nextTask.ID)
		if err != nil {
			return nil, nil, err
		}
	}

	return enrollment, nextTask, nil
}

func AdvanceTaskAfterSend(d *sql.DB, opts AdvanceOptions) (*Task, error) {
	if opts.TaskID == "" {
		return nil, fmt.Errorf("task ID is required")
	}
	if opts.SentAt.IsZero() {
		opts.SentAt = time.Now()
	}

	task, err := TaskByID(d, opts.TaskID)
	if err != nil {
		return nil, err
	}
	if task.Status != TaskStatusOpen {
		return nil, fmt.Errorf("task %s is %s", task.ID, task.Status)
	}

	enrollment, err := EnrollmentByID(d, task.EnrollmentID)
	if err != nil {
		return nil, err
	}

	template, err := TemplateByName(d, enrollment.SequenceName)
	if err != nil {
		return nil, err
	}

	tx, err := d.Begin()
	if err != nil {
		return nil, err
	}
	defer tx.Rollback()

	_, err = tx.Exec(`
		UPDATE follow_up_tasks
		SET status = ?, send_status = ?, completed_at = ?, updated_at = datetime('now')
		WHERE id = ?`,
		TaskStatusCompleted, TaskSendStatusSent, opts.SentAt.UTC().Format(time.RFC3339), task.ID,
	)
	if err != nil {
		return nil, err
	}
	if err := UpdateDraftStatusByTaskID(tx, task.ID, "sent"); err != nil {
		return nil, err
	}

	if task.StepNumber >= len(template.Steps) {
		_, err = tx.Exec(`
			UPDATE sequence_enrollments
			SET status = ?, current_step = ?, last_sent_at = ?, next_due_at = '',
				mailbox_id = CASE WHEN ? = '' THEN mailbox_id ELSE ? END,
				thread_id = CASE WHEN ? = '' THEN thread_id ELSE ? END,
				last_message_id = CASE WHEN ? = '' THEN last_message_id ELSE ? END,
				updated_at = datetime('now')
			WHERE id = ?`,
			StatusCompleted, task.StepNumber, opts.SentAt.UTC().Format(time.RFC3339),
			opts.MailboxID, opts.MailboxID,
			opts.ThreadID, opts.ThreadID, opts.MessageID, opts.MessageID, enrollment.ID,
		)
		if err != nil {
			return nil, err
		}

		if err := tx.Commit(); err != nil {
			return nil, err
		}
		return nil, nil
	}

	nextStep := template.Steps[task.StepNumber]
	nextDelay, err := stepDelay(nextStep)
	if err != nil {
		return nil, err
	}
	nextDueAt := opts.SentAt.Add(nextDelay).UTC()
	nextTaskID := newID("task")
	nextMailboxID := chooseString(opts.MailboxID, enrollment.MailboxID)
	nextThreadID := chooseString(opts.ThreadID, enrollment.ThreadID)
	renderEnrollment := *enrollment
	renderEnrollment.MailboxID = nextMailboxID
	renderEnrollment.ThreadID = nextThreadID
	renderEnrollment.LastMessageID = chooseString(opts.MessageID, enrollment.LastMessageID)
	nextSubject, nextBody := renderStep(nextStep, renderEnrollment)

	_, err = tx.Exec(`
		INSERT INTO follow_up_tasks (
			id, enrollment_id, mailbox_id, contact_email, subject, body, thread_id,
			step_number, step_name, send_type, status, send_status, due_at
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		nextTaskID, enrollment.ID, nextMailboxID, enrollment.ContactEmail,
		nextSubject, nextBody, nextThreadID, nextStep.StepNumber,
		nextStep.Name, nextStep.SendType, TaskStatusOpen, TaskSendStatusPending, nextDueAt.Format(time.RFC3339),
	)
	if err != nil {
		return nil, err
	}
	if err := UpsertDraftForTask(tx, nextTaskID, enrollment.ID, nextStep.StepNumber, nextSubject, nextBody, "sequence-runtime", "advance task"); err != nil {
		return nil, err
	}

	_, err = tx.Exec(`
		UPDATE sequence_enrollments
		SET current_step = ?, last_sent_at = ?, next_due_at = ?,
			mailbox_id = CASE WHEN ? = '' THEN mailbox_id ELSE ? END,
			thread_id = CASE WHEN ? = '' THEN thread_id ELSE ? END,
			last_message_id = CASE WHEN ? = '' THEN last_message_id ELSE ? END,
			updated_at = datetime('now')
		WHERE id = ?`,
		task.StepNumber, opts.SentAt.UTC().Format(time.RFC3339), nextDueAt.Format(time.RFC3339),
		nextMailboxID, nextMailboxID,
		opts.ThreadID, opts.ThreadID, opts.MessageID, opts.MessageID, enrollment.ID,
	)
	if err != nil {
		return nil, err
	}

	if err := tx.Commit(); err != nil {
		return nil, err
	}

	return TaskByID(d, nextTaskID)
}

func ListTasks(d *sql.DB, opts TaskListOptions) ([]Task, error) {
	if opts.Now.IsZero() {
		opts.Now = time.Now()
	}

	query := `
		SELECT
			t.id, t.enrollment_id, e.sequence_name, e.campaign_name, t.mailbox_id, m.email,
			t.contact_email, t.subject, t.thread_id, t.step_number, t.step_name,
			t.send_type, t.status, t.due_at, t.body, t.send_status, t.last_attempt_at, t.last_error, t.attempt_count
		FROM follow_up_tasks t
		JOIN sequence_enrollments e ON e.id = t.enrollment_id
		JOIN mailboxes m ON m.id = t.mailbox_id
		WHERE t.status = ? AND e.status = ?`
	args := []any{TaskStatusOpen, StatusActive}

	if !opts.IncludeFuture {
		query += " AND t.due_at <= ?"
		args = append(args, opts.Now.UTC().Format(time.RFC3339))
	}

	query += " ORDER BY t.due_at ASC"
	if opts.Limit > 0 {
		query += fmt.Sprintf(" LIMIT %d", opts.Limit)
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var tasks []Task
	for rows.Next() {
		var task Task
		if err := rows.Scan(
			&task.ID, &task.EnrollmentID, &task.SequenceName, &task.CampaignName, &task.MailboxID,
			&task.MailboxEmail, &task.ContactEmail, &task.Subject, &task.ThreadID,
			&task.StepNumber, &task.StepName, &task.SendType, &task.Status, &task.DueAt,
			&task.Body, &task.SendStatus, &task.LastAttemptAt, &task.LastError, &task.AttemptCount,
		); err != nil {
			return nil, err
		}
		task.DaysUntilDue = daysUntil(task.DueAt, opts.Now)
		tasks = append(tasks, task)
	}

	return tasks, rows.Err()
}

func ListDispatchTasks(d *sql.DB, now time.Time, limit int) ([]DispatchTask, error) {
	return ListDispatchTasksForTransport(d, DispatchOptions{
		Limit: limit,
		Now:   now,
	})
}

func ListDispatchTasksForTransport(d *sql.DB, opts DispatchOptions) ([]DispatchTask, error) {
	if opts.Now.IsZero() {
		opts.Now = time.Now()
	}

	tasks, err := ListTasks(d, TaskListOptions{
		IncludeFuture: false,
		Limit:         opts.Limit,
		Now:           opts.Now,
	})
	if err != nil {
		return nil, err
	}

	dispatch := make([]DispatchTask, 0, len(tasks))
	for _, task := range tasks {
		item := DispatchTask{Task: task, Ready: true}
		if suppression, suppressed, err := IsSuppressed(d, task.ContactEmail); err != nil {
			return nil, err
		} else if suppressed {
			item.Ready = false
			item.BlockedReason = fmt.Sprintf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
			dispatch = append(dispatch, item)
			continue
		}

		mailbox, err := ResolveTaskMailbox(d, task, opts.TransportEmail, opts.Now)
		if err != nil {
			item.Ready = false
			item.BlockedReason = err.Error()
			dispatch = append(dispatch, item)
			continue
		}
		item.SelectedMailboxID = mailbox.ID
		item.SelectedMailboxEmail = mailbox.Email
		item.TransportEmail = effectiveTransportEmail(*mailbox)
		item.RenderedSubject, item.RenderedBody, err = RenderTaskContent(d, task)
		if err != nil {
			return nil, err
		}
		dispatch = append(dispatch, item)
	}
	return dispatch, nil
}

func TaskByID(d *sql.DB, taskID string) (*Task, error) {
	row := d.QueryRow(`
		SELECT
			t.id, t.enrollment_id, e.sequence_name, e.campaign_name, t.mailbox_id, m.email,
			t.contact_email, t.subject, t.thread_id, t.step_number, t.step_name,
			t.send_type, t.status, t.due_at, t.body, t.send_status, t.last_attempt_at, t.last_error, t.attempt_count
		FROM follow_up_tasks t
		JOIN sequence_enrollments e ON e.id = t.enrollment_id
		JOIN mailboxes m ON m.id = t.mailbox_id
		WHERE t.id = ?`,
		taskID,
	)

	var task Task
	if err := row.Scan(
		&task.ID, &task.EnrollmentID, &task.SequenceName, &task.CampaignName, &task.MailboxID,
		&task.MailboxEmail, &task.ContactEmail, &task.Subject, &task.ThreadID,
		&task.StepNumber, &task.StepName, &task.SendType, &task.Status, &task.DueAt,
		&task.Body, &task.SendStatus, &task.LastAttemptAt, &task.LastError, &task.AttemptCount,
	); err != nil {
		if err == sql.ErrNoRows {
			return nil, fmt.Errorf("task %q not found", taskID)
		}
		return nil, err
	}

	task.DaysUntilDue = daysUntil(task.DueAt, time.Now())
	return &task, nil
}

func SnoozeTask(d *sql.DB, taskID string, byDays int) (*Task, error) {
	if byDays <= 0 {
		byDays = 1
	}
	task, err := TaskByID(d, taskID)
	if err != nil {
		return nil, err
	}
	if task.Status != TaskStatusOpen {
		return nil, fmt.Errorf("task %s is %s", task.ID, task.Status)
	}

	dueAt, err := time.Parse(time.RFC3339, task.DueAt)
	if err != nil {
		return nil, fmt.Errorf("parsing due_at for task %s: %w", task.ID, err)
	}
	newDueAt := dueAt.AddDate(0, 0, byDays).UTC().Format(time.RFC3339)

	_, err = d.Exec(`
		UPDATE follow_up_tasks
		SET due_at = ?, updated_at = datetime('now')
		WHERE id = ?`,
		newDueAt, task.ID,
	)
	if err != nil {
		return nil, err
	}

	if _, err := d.Exec(`
		UPDATE sequence_enrollments
		SET next_due_at = ?, updated_at = datetime('now')
		WHERE id = ?`,
		newDueAt, task.EnrollmentID,
	); err != nil {
		return nil, err
	}

	return TaskByID(d, task.ID)
}

func CancelTask(d *sql.DB, taskID, reason string) error {
	task, err := TaskByID(d, taskID)
	if err != nil {
		return err
	}

	_, err = d.Exec(`
		UPDATE follow_up_tasks
		SET status = ?, send_status = ?, canceled_reason = ?, updated_at = datetime('now')
		WHERE id = ?`,
		TaskStatusCanceled, TaskSendStatusFailed, reason, task.ID,
	)
	if err != nil {
		return err
	}
	if err := UpdateDraftStatusByTaskID(d, task.ID, "canceled"); err != nil && !isNotFound(err) {
		return err
	}

	_, err = d.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, status_reason = ?, next_due_at = '', updated_at = datetime('now')
		WHERE id = ? AND status IN (?, ?)`,
		StatusStopped, reason, task.EnrollmentID, StatusActive, StatusPaused,
	)
	return err
}

func PauseEnrollment(d *sql.DB, enrollmentID string) error {
	_, err := d.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, updated_at = datetime('now')
		WHERE id = ? AND status != ?`,
		StatusPaused, enrollmentID, StatusCompleted,
	)
	return err
}

func ResumeEnrollment(d *sql.DB, enrollmentID string) error {
	_, err := d.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, updated_at = datetime('now')
		WHERE id = ? AND status = ?`,
		StatusActive, enrollmentID, StatusPaused,
	)
	return err
}

func UpdateMailboxPolicy(d *sql.DB, mailboxEmail string, opts MailboxPolicyOptions) (*Mailbox, error) {
	mailbox, err := mailboxByEmail(d, mailboxEmail)
	if err != nil {
		return nil, err
	}

	args := []any{}
	sets := []string{}
	if opts.Status != "" {
		sets = append(sets, "status = ?")
		args = append(args, opts.Status)
	}
	if opts.TransportEmail != "" {
		sets = append(sets, "transport_email = ?")
		args = append(args, opts.TransportEmail)
	}
	if opts.RotationGroup != "" {
		sets = append(sets, "rotation_group = ?")
		args = append(args, opts.RotationGroup)
	}
	if opts.WarmupStage != "" {
		sets = append(sets, "warmup_stage = ?")
		args = append(args, opts.WarmupStage)
		if strings.EqualFold(opts.WarmupStage, "warming") || strings.EqualFold(opts.WarmupStage, "ramping") {
			sets = append(sets, "warmup_started_at = CASE WHEN warmup_started_at = '' THEN datetime('now') ELSE warmup_started_at END")
		}
	}
	if opts.FirstTouchDailyCap != nil {
		sets = append(sets, "first_touch_daily_cap = ?")
		args = append(args, *opts.FirstTouchDailyCap)
	}
	if opts.FollowUpDailyCap != nil {
		sets = append(sets, "follow_up_daily_cap = ?")
		args = append(args, *opts.FollowUpDailyCap)
	}
	if opts.ReplyDailyCap != nil {
		sets = append(sets, "reply_daily_cap = ?")
		args = append(args, *opts.ReplyDailyCap)
	}
	if opts.MinGapMinutes != nil {
		sets = append(sets, "min_gap_minutes = ?")
		args = append(args, *opts.MinGapMinutes)
	}
	if opts.SendWindowStartHour != nil {
		sets = append(sets, "send_window_start_hour = ?")
		args = append(args, *opts.SendWindowStartHour)
	}
	if opts.SendWindowEndHour != nil {
		sets = append(sets, "send_window_end_hour = ?")
		args = append(args, *opts.SendWindowEndHour)
	}
	if opts.SendWindowTimezone != "" {
		sets = append(sets, "send_window_timezone = ?")
		args = append(args, opts.SendWindowTimezone)
	}
	if opts.ReputationScore != nil {
		sets = append(sets, "reputation_score = ?")
		args = append(args, *opts.ReputationScore)
	}
	if opts.Priority != nil {
		sets = append(sets, "priority = ?")
		args = append(args, *opts.Priority)
	}
	if opts.RestartWarmup {
		sets = append(sets, "warmup_started_at = datetime('now')")
	}
	if len(sets) == 0 {
		return mailbox, nil
	}

	args = append(args, mailbox.ID)
	_, err = d.Exec(
		fmt.Sprintf("UPDATE mailboxes SET %s, updated_at = datetime('now') WHERE id = ?", strings.Join(sets, ", ")),
		args...,
	)
	if err != nil {
		return nil, err
	}

	return mailboxByEmail(d, mailboxEmail)
}

func ActiveEnrollmentForContact(d *sql.DB, mailboxID, contactEmail string) (*Enrollment, error) {
	row := d.QueryRow(`
		SELECT id
		FROM sequence_enrollments
		WHERE mailbox_id = ? AND lower(contact_email) = lower(?) AND status IN (?, ?)
