func AddSuppression(d *sql.DB, scope, value, reason, source string) (*Suppression, error) {
	scope = normalizeSuppressionScope(scope)
	value = normalizeSuppressionValue(scope, value)
	if value == "" {
		return nil, fmt.Errorf("suppression value is required")
	}
	if source == "" {
		source = "manual"
	}

	_, err := d.Exec(`
		INSERT INTO suppressions (id, scope, value, reason, source)
		VALUES (?, ?, ?, ?, ?)
		ON CONFLICT(scope, value) DO UPDATE SET
			reason = excluded.reason,
			source = excluded.source`,
		newID("sup"), scope, value, reason, source,
	)
	if err != nil {
		return nil, err
	}

	return suppressionByScopeValue(d, scope, value)
}

func RemoveSuppression(d *sql.DB, scope, value string) error {
	scope = normalizeSuppressionScope(scope)
	value = normalizeSuppressionValue(scope, value)
	_, err := d.Exec(`DELETE FROM suppressions WHERE scope = ? AND value = ?`, scope, value)
	return err
}

func ListSuppressions(d *sql.DB, scope string, limit int) ([]Suppression, error) {
	query := `SELECT id, scope, value, reason, source, created_at FROM suppressions`
	var args []any
	if scope != "" {
		query += ` WHERE scope = ?`
		args = append(args, normalizeSuppressionScope(scope))
	}
	query += ` ORDER BY created_at DESC`
	if limit > 0 {
		query += fmt.Sprintf(" LIMIT %d", limit)
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var suppressions []Suppression
	for rows.Next() {
		var item Suppression
		if err := rows.Scan(&item.ID, &item.Scope, &item.Value, &item.Reason, &item.Source, &item.CreatedAt); err != nil {
			return nil, err
		}
		suppressions = append(suppressions, item)
	}
	return suppressions, rows.Err()
}

func IsSuppressed(d *sql.DB, email string) (*Suppression, bool, error) {
	email = normalizeSuppressionValue("email", email)
	if email == "" {
		return nil, false, nil
	}

	if suppression, err := suppressionByScopeValue(d, "email", email); err == nil {
		return suppression, true, nil
	} else if !isNotFound(err) {
		return nil, false, err
	}

	domain := domainFromEmail(email)
	if domain == "" {
		return nil, false, nil
	}
	if suppression, err := suppressionByScopeValue(d, "domain", domain); err == nil {
		return suppression, true, nil
	} else if !isNotFound(err) {
		return nil, false, err
	}

	return nil, false, nil
}

func RecordReply(d *sql.DB, opts ReplyOptions) (*ReplyEvent, error) {
	if opts.EnrollmentID == "" {
		return nil, fmt.Errorf("enrollment ID is required")
	}
	if opts.MessageID == "" {
		return nil, fmt.Errorf("message ID is required")
	}
	if opts.OccurredAt.IsZero() {
		opts.OccurredAt = time.Now()
	}
	enrollment, err := EnrollmentByID(d, opts.EnrollmentID)
	if err != nil {
		return nil, err
	}
	if opts.MailboxID == "" {
		opts.MailboxID = enrollment.MailboxID
	}
	if opts.ThreadID == "" {
		opts.ThreadID = enrollment.ThreadID
	}
	if opts.ContactEmail == "" {
		opts.ContactEmail = enrollment.ContactEmail
	}
	normalizedContact := normalizeSuppressionValue("email", opts.ContactEmail)
	classification := normalizeReplyClassification(opts.Classification)

	if existing, err := replyEventByMessageID(d, opts.MessageID); err == nil {
		return existing, nil
	} else if !isNotFound(err) {
		return nil, err
	}

	tx, err := d.Begin()
	if err != nil {
		return nil, err
	}
	defer tx.Rollback()

	replyID := newID("reply")
	_, err = tx.Exec(`
		INSERT INTO reply_events (
			id, enrollment_id, mailbox_id, thread_id, message_id, contact_email,
			classification, status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		replyID, opts.EnrollmentID, opts.MailboxID, opts.ThreadID, opts.MessageID, normalizedContact,
		classification, replyStatus(classification), "", opts.Subject, opts.Snippet, "", "", opts.OccurredAt.UTC().Format(time.RFC3339),
	)
	if err != nil {
		return nil, err
	}

	enrollmentStatus := StatusPaused
	statusReason := "reply:" + classification
	if classification == "not_interested" || classification == "unsubscribe" || classification == "bounced" {
		enrollmentStatus = StatusStopped
	}

	_, err = tx.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, status_reason = ?, reply_state = ?, last_reply_at = ?, next_due_at = '', updated_at = datetime('now')
		WHERE lower(contact_email) = lower(?) AND status IN (?, ?)`,
		enrollmentStatus, statusReason, classification, opts.OccurredAt.UTC().Format(time.RFC3339), normalizedContact, StatusActive, StatusPaused,
	)
	if err != nil {
		return nil, err
	}

	_, err = tx.Exec(`
		UPDATE follow_up_tasks
		SET status = ?, canceled_reason = ?, updated_at = datetime('now')
		WHERE enrollment_id IN (
			SELECT id FROM sequence_enrollments WHERE lower(contact_email) = lower(?)
		) AND status = ?`,
		TaskStatusCanceled, statusReason, normalizedContact, TaskStatusOpen,
	)
	if err != nil {
		return nil, err
	}

	if classification == "not_interested" || classification == "unsubscribe" || classification == "bounced" {
		if _, err := tx.Exec(`
			INSERT INTO suppressions (id, scope, value, reason, source)
			VALUES (?, 'email', ?, ?, 'reply')
			ON CONFLICT(scope, value) DO UPDATE SET reason = excluded.reason, source = excluded.source`,
			newID("sup"), normalizedContact, statusReason,
		); err != nil {
			return nil, err
		}
	}
	if classification == "bounced" {
		if _, err := tx.Exec(`
			UPDATE mailboxes
			SET last_bounce_at = ?,
				reputation_score = CASE
					WHEN reputation_score >= 15 THEN reputation_score - 15
					ELSE 0
				END,
				status = CASE
					WHEN reputation_score - 15 <= 40 THEN 'unhealthy'
					ELSE status
				END,
				updated_at = datetime('now')
			WHERE id = ?`,
			opts.OccurredAt.UTC().Format(time.RFC3339), opts.MailboxID,
		); err != nil {
			return nil, err
		}
		if err := maybeAutoSuppressDomainForBounces(tx, normalizedContact, statusReason, opts.OccurredAt); err != nil {
			return nil, err
		}
	}

	if err := tx.Commit(); err != nil {
		return nil, err
	}

	return replyEventByMessageID(d, opts.MessageID)
}

func ListReplyEvents(d *sql.DB, limit int) ([]ReplyEvent, error) {
	query := `SELECT id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, classification, status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at FROM reply_events ORDER BY occurred_at DESC`
	if limit > 0 {
