func ListLeads(d *sql.DB, limit int, includeSuppressed bool) ([]Lead, error) {
	query := `
		SELECT
			c.email, MAX(c.name), MAX(c.domain), MAX(c.company), MAX(c.title), MAX(c.owner),
			MAX(c.lead_status), MAX(COALESCE(c.last_activity_at, '')), MAX(c.email_count),
			COALESCE(se.status, ''), COALESCE(se.sequence_name, ''), COALESCE(se.campaign_name, ''),
			CASE WHEN se_sup.id IS NOT NULL OR sd_sup.id IS NOT NULL THEN 1 ELSE 0 END,
			COALESCE(se_sup.reason, sd_sup.reason, '')
		FROM contacts c
		LEFT JOIN sequence_enrollments se
			ON se.id = (
				SELECT id FROM sequence_enrollments
				WHERE contact_email = c.email
				ORDER BY updated_at DESC
					LIMIT 1
				)
		LEFT JOIN suppressions se_sup
			ON se_sup.scope = 'email' AND se_sup.value = lower(c.email)
		LEFT JOIN suppressions sd_sup
			ON sd_sup.scope = 'domain' AND sd_sup.value = lower(c.domain)
		GROUP BY c.email, se.status, se.sequence_name, se.campaign_name, se_sup.id, se_sup.reason, sd_sup.id, sd_sup.reason
		ORDER BY MAX(COALESCE(c.last_activity_at, '')) DESC, c.email ASC`
	if limit > 0 {
		query += fmt.Sprintf(" LIMIT %d", limit)
	}

	rows, err := d.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var leads []Lead
	for rows.Next() {
		var lead Lead
		var suppressed int
		if err := rows.Scan(
			&lead.Email, &lead.Name, &lead.Domain, &lead.Company, &lead.Title, &lead.Owner,
			&lead.LeadStatus, &lead.LastActivityAt, &lead.EmailCount,
			&lead.EnrollmentStatus, &lead.SequenceName, &lead.CampaignName,
			&suppressed, &lead.SuppressionReason,
		); err != nil {
			return nil, err
		}
		lead.Suppressed = suppressed == 1
		if !includeSuppressed && lead.Suppressed {
			continue
		}
		leads = append(leads, lead)
	}

	return leads, rows.Err()
}

func AnalyticsSummary(d *sql.DB, now time.Time) (*SequenceAnalyticsSummary, error) {
	if now.IsZero() {
		now = time.Now()
	}

	summary := &SequenceAnalyticsSummary{
		GeneratedAt:  now.UTC().Format(time.RFC3339),
		ReplyClasses: map[string]int{},
	}

	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusActive).Scan(&summary.ActiveEnrollments); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusPaused).Scan(&summary.PausedEnrollments); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusCompleted).Scan(&summary.CompletedEnrollments); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusStopped).Scan(&summary.StoppedEnrollments); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM follow_up_tasks WHERE status = ?`, TaskStatusOpen).Scan(&summary.OpenTasks); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM follow_up_tasks WHERE status = ?`, TaskStatusCompleted).Scan(&summary.CompletedTasks); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM follow_up_tasks WHERE status = ?`, TaskStatusCanceled).Scan(&summary.CanceledTasks); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM reply_events`).Scan(&summary.ReplyCount); err != nil {
		return nil, err
	}
	if err := d.QueryRow(`SELECT COUNT(*) FROM suppressions`).Scan(&summary.SuppressionCount); err != nil {
		return nil, err
	}

	replyRows, err := d.Query(`SELECT classification, COUNT(*) FROM reply_events GROUP BY classification ORDER BY COUNT(*) DESC`)
	if err != nil {
		return nil, err
	}
	defer replyRows.Close()
	for replyRows.Next() {
		var classification string
		var count int
		if err := replyRows.Scan(&classification, &count); err != nil {
			return nil, err
		}
		summary.ReplyClasses[classification] = count
	}
	if err := replyRows.Err(); err != nil {
		return nil, err
	}

	sequenceRows, err := d.Query(`
		SELECT
			e.sequence_name,
			COUNT(DISTINCT CASE WHEN e.status = 'active' THEN e.id END),
			COUNT(DISTINCT CASE WHEN e.status = 'paused' THEN e.id END),
			COUNT(DISTINCT CASE WHEN e.status = 'completed' THEN e.id END),
			COUNT(DISTINCT CASE WHEN e.status = 'stopped' THEN e.id END),
			COUNT(DISTINCT CASE WHEN t.status = 'open' THEN t.id END),
			COUNT(DISTINCT r.id)
		FROM sequence_enrollments e
		LEFT JOIN follow_up_tasks t ON t.enrollment_id = e.id
		LEFT JOIN reply_events r ON r.enrollment_id = e.id
		GROUP BY e.sequence_name
		ORDER BY e.sequence_name ASC`)
	if err != nil {
		return nil, err
	}
	defer sequenceRows.Close()
	for sequenceRows.Next() {
		var item SequencePerformance
		if err := sequenceRows.Scan(
			&item.Name,
			&item.ActiveEnrollments,
			&item.PausedEnrollments,
			&item.CompletedEnrollments,
			&item.StoppedEnrollments,
			&item.OpenTasks,
			&item.ReplyCount,
		); err != nil {
			return nil, err
		}
		summary.BySequence = append(summary.BySequence, item)
	}
	if err := sequenceRows.Err(); err != nil {
		return nil, err
	}

	mailboxRows, err := d.Query(`
		SELECT
			m.email,
			COALESCE(u.first_touches_sent, 0),
			COALESCE(u.follow_ups_sent, 0),
			COALESCE(u.replies_sent, 0),
			SUM(CASE WHEN e.status = 'active' THEN 1 ELSE 0 END),
			SUM(CASE WHEN e.status = 'paused' THEN 1 ELSE 0 END),
			SUM(CASE WHEN e.status = 'completed' THEN 1 ELSE 0 END)
		FROM mailboxes m
		LEFT JOIN mailbox_daily_usage u
			ON u.mailbox_id = m.id AND u.usage_day = ?
		LEFT JOIN sequence_enrollments e ON e.mailbox_id = m.id
		GROUP BY m.id, m.email, u.first_touches_sent, u.follow_ups_sent, u.replies_sent
		ORDER BY m.email ASC`,
		dayKey(now),
	)
	if err != nil {
		return nil, err
	}
	defer mailboxRows.Close()
	for mailboxRows.Next() {
		var item MailboxPerformance
		if err := mailboxRows.Scan(
			&item.MailboxEmail,
			&item.FirstTouchesSent,
			&item.FollowUpsSent,
			&item.RepliesSent,
			&item.ActiveEnrollments,
			&item.PausedEnrollments,
			&item.CompletedEnrollments,
		); err != nil {
			return nil, err
		}
		summary.ByMailbox = append(summary.ByMailbox, item)
	}
	if err := mailboxRows.Err(); err != nil {
		return nil, err
	}

	return summary, nil
}

