func ResolveTaskMailbox(d *sql.DB, task Task, transportEmail string, now time.Time) (*Mailbox, error) {
	if now.IsZero() {
		now = time.Now()
	}

	primary, err := mailboxByID(d, task.MailboxID)
	if err != nil {
		return nil, err
	}

	if transportEmail == "" {
		if err := CanSend(d, primary.ID, task.SendType, now); err != nil {
			return nil, err
		}
		return primary, nil
	}

	candidates, err := rotationCandidates(d, *primary, task.SendType, transportEmail, now)
	if err != nil {
		return nil, err
	}
	if len(candidates) == 0 {
		return nil, fmt.Errorf("no mailbox in rotation group %q is ready for transport %s", primary.RotationGroup, transportEmail)
	}
	return candidates[0], nil
}

func rotationCandidates(d *sql.DB, primary Mailbox, sendType, transportEmail string, now time.Time) ([]*Mailbox, error) {
	rows, err := d.Query(`
		SELECT id, email, transport_email, rotation_group, provider, status, warmup_stage, warmup_started_at,
			first_touch_daily_cap, follow_up_daily_cap, reply_daily_cap, min_gap_minutes,
			send_window_start_hour, send_window_end_hour, send_window_timezone,
			reputation_score, priority, last_used_at, last_bounce_at,
			COALESCE(u.first_touches_sent, 0), COALESCE(u.follow_ups_sent, 0), COALESCE(u.replies_sent, 0)
		FROM mailboxes
		LEFT JOIN mailbox_daily_usage u
			ON u.mailbox_id = mailboxes.id AND u.usage_day = ?
		WHERE provider = ? AND rotation_group = ?
		ORDER BY email ASC`,
		dayKey(now), primary.Provider, primary.RotationGroup,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	type candidate struct {
		mailbox          *Mailbox
		firstTouchesSent int
		followUpsSent    int
		repliesSent      int
		remaining        int
	}

	var rawCandidates []candidate
	blocked := map[string]string{}
	for rows.Next() {
		var item Mailbox
		var firstTouchesSent, followUpsSent, repliesSent int
		if err := rows.Scan(
			&item.ID, &item.Email, &item.TransportEmail, &item.RotationGroup, &item.Provider, &item.Status, &item.WarmupStage, &item.WarmupStartedAt,
			&item.FirstTouchDailyCap, &item.FollowUpDailyCap, &item.ReplyDailyCap, &item.MinGapMinutes,
			&item.SendWindowStartHour, &item.SendWindowEndHour, &item.SendWindowTimezone,
			&item.ReputationScore, &item.Priority, &item.LastUsedAt, &item.LastBounceAt,
			&firstTouchesSent, &followUpsSent, &repliesSent,
		); err != nil {
			return nil, err
		}
		if !strings.EqualFold(effectiveTransportEmail(item), transportEmail) {
			continue
		}
		rawCandidates = append(rawCandidates, candidate{
			mailbox:          &item,
			firstTouchesSent: firstTouchesSent,
			followUpsSent:    followUpsSent,
			repliesSent:      repliesSent,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}

	candidates := make([]candidate, 0, len(rawCandidates))
	for _, item := range rawCandidates {
		if err := CanSend(d, item.mailbox.ID, sendType, now); err != nil {
			blocked[item.mailbox.ID] = err.Error()
			continue
		}

		firstTouchCap, followUpCap, replyCap := effectiveCaps(*item.mailbox, now)
		switch NormalizeSendType(sendType) {
		case SendTypeFirstTouch:
			item.remaining = remaining(firstTouchCap, item.firstTouchesSent)
		case SendTypeFollowUp:
			item.remaining = remaining(followUpCap, item.followUpsSent)
		case SendTypeReply:
			item.remaining = remaining(replyCap, item.repliesSent)
		default:
			item.remaining = -1
		}
		candidates = append(candidates, item)
	}

	sort.SliceStable(candidates, func(i, j int) bool {
		left := candidates[i]
		right := candidates[j]
		if left.mailbox.ID == primary.ID && right.mailbox.ID != primary.ID {
			return true
		}
		if right.mailbox.ID == primary.ID && left.mailbox.ID != primary.ID {
			return false
		}
		if left.mailbox.Priority != right.mailbox.Priority {
			return left.mailbox.Priority > right.mailbox.Priority
		}
		if left.mailbox.ReputationScore != right.mailbox.ReputationScore {
			return left.mailbox.ReputationScore > right.mailbox.ReputationScore
		}
		if left.remaining != right.remaining {
			return left.remaining > right.remaining
		}
		leftUsed := parseOptionalTime(left.mailbox.LastUsedAt)
		rightUsed := parseOptionalTime(right.mailbox.LastUsedAt)
		if leftUsed.IsZero() != rightUsed.IsZero() {
			return leftUsed.IsZero()
		}
		if !leftUsed.Equal(rightUsed) {
			return leftUsed.Before(rightUsed)
		}
		return left.mailbox.Email < right.mailbox.Email
	})

	if len(candidates) == 0 {
		if reason := blocked[primary.ID]; reason != "" {
			return nil, fmt.Errorf("%s", reason)
		}
	}

	result := make([]*Mailbox, 0, len(candidates))
	for _, item := range candidates {
		result = append(result, item.mailbox)
	}
	return result, nil
}

func usageColumn(sendType string) string {
	switch NormalizeSendType(sendType) {
	case SendTypeFirstTouch:
		return "first_touches_sent"
	case SendTypeFollowUp:
		return "follow_ups_sent"
	case SendTypeReply:
		return "replies_sent"
	default:
		return ""
	}
}

func latestMailboxOutboundAt(d *sql.DB, mailboxEmail string) (time.Time, error) {
	row := d.QueryRow(`
		SELECT date
		FROM emails
		WHERE lower(from_email) = lower(?) AND direction = 'outbound'
		ORDER BY date DESC
		LIMIT 1`,
		mailboxEmail,
	)

	var value string
	if err := row.Scan(&value); err != nil {
		if err == sql.ErrNoRows {
			return time.Time{}, nil
		}
		return time.Time{}, err
	}

	for _, layout := range []string{
		time.RFC3339,
		time.RFC1123Z,
		"Mon, 2 Jan 2006 15:04:05 -0700",
		"2006-01-02 15:04:05",
		"2006-01-02",
	} {
		if ts, err := time.Parse(layout, value); err == nil {
			return ts.UTC(), nil
		}
	}
	return time.Time{}, nil
}

func RenderTaskContent(d *sql.DB, task Task) (string, string, error) {
	subject := strings.TrimSpace(task.Subject)
	body := strings.TrimSpace(task.Body)
	if subject != "" && body != "" {
		return subject, body, nil
	}
	if draft, err := DraftByTaskID(d, task.ID); err == nil {
		if subject == "" {
			subject = strings.TrimSpace(draft.Subject)
		}
		if body == "" {
			body = strings.TrimSpace(draft.Body)
		}
		if subject != "" && body != "" {
			return subject, body, nil
		}
	}

	enrollment, err := EnrollmentByID(d, task.EnrollmentID)
	if err != nil {
		return "", "", err
	}
	template, err := TemplateByName(d, enrollment.SequenceName)
	if err != nil {
		return "", "", err
	}
	step, ok := templateStep(template, task.StepNumber)
	if !ok {
		if subject == "" {
			subject = enrollment.Subject
		}
		return subject, body, nil
	}
	renderedSubject, renderedBody := renderStep(step, *enrollment)
	if subject == "" {
		subject = renderedSubject
	}
	if body == "" {
		body = renderedBody
	}
	return subject, body, nil
}

func MarkTaskAttempt(d *sql.DB, taskID string, attemptedAt time.Time, attemptErr error) error {
	if attemptedAt.IsZero() {
		attemptedAt = time.Now()
	}
	lastError := ""
	if attemptErr != nil {
		lastError = attemptErr.Error()
	}
	_, err := d.Exec(`
		UPDATE follow_up_tasks
		SET attempt_count = attempt_count + 1,
			last_attempt_at = ?,
			last_error = ?,
			send_status = CASE
				WHEN ? = '' THEN send_status
				ELSE ?
			END,
			updated_at = datetime('now')
		WHERE id = ?`,
		attemptedAt.UTC().Format(time.RFC3339), lastError, failedStatus(lastError), failedStatus(lastError), taskID,
	)
	return err
}

func renderStep(step TemplateStep, enrollment Enrollment) (string, string) {
	subjectTemplate := strings.TrimSpace(step.SubjectTemplate)
	if subjectTemplate == "" {
		subjectTemplate = "{{subject}}"
	}
	bodyTemplate := strings.TrimSpace(step.BodyTemplate)
	if bodyTemplate == "" {
		bodyTemplate = enrollment.InitialBody
	}

	subject := renderTemplate(subjectTemplate, enrollment)
	body := renderTemplate(bodyTemplate, enrollment)
	if subject == "" {
		subject = enrollment.Subject
	}
	if body == "" {
		body = enrollment.InitialBody
	}
	return strings.TrimSpace(subject), strings.TrimSpace(body)
}

func renderTemplate(input string, enrollment Enrollment) string {
	greeting := "Hi there,"
	if name := firstName(enrollment.ContactName); name != "" {
		greeting = "Hi " + name + ","
	}
	companyHint := "your team"
	if domain := domainFromEmail(enrollment.ContactEmail); domain != "" {
		companyHint = domain
	}

	replacer := strings.NewReplacer(
		"{{subject}}", strings.TrimSpace(enrollment.Subject),
		"{{initial_body}}", strings.TrimSpace(enrollment.InitialBody),
		"{{contact_email}}", strings.TrimSpace(enrollment.ContactEmail),
		"{{contact_name}}", strings.TrimSpace(enrollment.ContactName),
		"{{first_name}}", firstName(enrollment.ContactName),
		"{{greeting}}", greeting,
		"{{company_hint}}", companyHint,
	)
	return replacer.Replace(strings.TrimSpace(input))
}

func templateStep(template Template, stepNumber int) (TemplateStep, bool) {
	for _, step := range template.Steps {
		if step.StepNumber == stepNumber {
			return step, true
		}
	}
	return TemplateStep{}, false
}

func effectiveTransportEmail(mailbox Mailbox) string {
	if strings.TrimSpace(mailbox.TransportEmail) != "" {
		return strings.TrimSpace(mailbox.TransportEmail)
	}
	return strings.TrimSpace(mailbox.Email)
}

func effectiveCaps(mailbox Mailbox, now time.Time) (int, int, int) {
	if now.IsZero() {
		now = time.Now()
	}
	firstTouchCap := mailbox.FirstTouchDailyCap
	followUpCap := mailbox.FollowUpDailyCap
	replyCap := mailbox.ReplyDailyCap

	switch strings.ToLower(strings.TrimSpace(mailbox.WarmupStage)) {
	case "warming":
		day := warmupDay(mailbox, now)
		firstTouchCap = minPositive(firstTouchCap, 3+day*2)
		followUpCap = minPositive(followUpCap, 6+day*4)
	case "ramping":
		day := warmupDay(mailbox, now)
		firstTouchCap = minPositive(firstTouchCap, 5+day*5)
		followUpCap = minPositive(followUpCap, 10+day*10)
	}

	switch {
	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 70:
		firstTouchCap = scaledCap(firstTouchCap, 0.5)
		followUpCap = scaledCap(followUpCap, 0.75)
	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 85:
		firstTouchCap = scaledCap(firstTouchCap, 0.75)
	}

	return firstTouchCap, followUpCap, replyCap
}

func mailboxRemainingCapacity(d *sql.DB, mailboxID, sendType string, now time.Time) (int, error) {
	mailbox, usage, err := mailboxAndUsage(d, mailboxID, now)
	if err != nil {
		return 0, err
	}
	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox, now)
	switch NormalizeSendType(sendType) {
	case SendTypeFirstTouch:
		return remaining(firstTouchCap, usage.FirstTouchesSent), nil
	case SendTypeFollowUp:
		return remaining(followUpCap, usage.FollowUpsSent), nil
	case SendTypeReply:
		return remaining(replyCap, usage.RepliesSent), nil
	default:
		return -1, nil
	}
}

func withinSendWindow(mailbox Mailbox, now time.Time) bool {
	start := clampHour(mailbox.SendWindowStartHour)
	end := clampHour(mailbox.SendWindowEndHour)
	if start == end {
		return true
	}

	loc := time.Local
	tz := strings.TrimSpace(mailbox.SendWindowTimezone)
	if tz != "" && !strings.EqualFold(tz, "local") {
		if loaded, err := time.LoadLocation(tz); err == nil {
			loc = loaded
		}
	}
	hour := now.In(loc).Hour()
	if start < end {
		return hour >= start && hour < end
	}
	return hour >= start || hour < end
}

func clampHour(hour int) int {
	if hour < 0 {
		return 0
	}
	if hour > 23 {
		return 23
	}
	return hour
}

func scaledCap(cap int, factor float64) int {
	if cap <= 0 {
		return cap
	}
	scaled := int(float64(cap) * factor)
	if scaled < 1 {
		scaled = 1
	}
	if scaled > cap {
		scaled = cap
	}
	return scaled
}

func minPositive(value, ceiling int) int {
	if value <= 0 {
		return value
	}
	if ceiling <= 0 {
		return value
	}
	if value < ceiling {
		return value
	}
	return ceiling
}

func firstName(name string) string {
	name = strings.TrimSpace(name)
	if name == "" {
		return ""
	}
	parts := strings.Fields(name)
	if len(parts) == 0 {
		return ""
	}
	return parts[0]
}

func parseOptionalTime(value string) time.Time {
	if value == "" {
		return time.Time{}
	}
	ts, _ := time.Parse(time.RFC3339, value)
	return ts
}

func stepDelay(step TemplateStep) (time.Duration, error) {
	delay := strings.TrimSpace(step.Delay)
	if delay == "" {
		return 0, nil
	}

	parsed, err := time.ParseDuration(delay)
	if err != nil {
		return 0, fmt.Errorf("parsing delay %q for sequence step %d (%s): %w", delay, step.StepNumber, step.Name, err)
	}
	return parsed, nil
}

func defaultCampaignName(opts EnrollmentOptions) string {
	if strings.TrimSpace(opts.CampaignName) != "" {
		return strings.TrimSpace(opts.CampaignName)
	}
	if strings.TrimSpace(opts.SequenceName) != "" {
		return strings.TrimSpace(opts.SequenceName)
	}
	return DefaultTemplateName
}

func suppressionByScopeValue(d *sql.DB, scope, value string) (*Suppression, error) {
	row := d.QueryRow(`SELECT id, scope, value, reason, source, created_at FROM suppressions WHERE scope = ? AND value = ?`, scope, value)
	var item Suppression
	if err := row.Scan(&item.ID, &item.Scope, &item.Value, &item.Reason, &item.Source, &item.CreatedAt); err != nil {
		if err == sql.ErrNoRows {
			return nil, fmt.Errorf("suppression %s:%s not found", scope, value)
		}
		return nil, err
	}
	return &item, nil
}

func replyEventByMessageID(d *sql.DB, messageID string) (*ReplyEvent, error) {
	row := d.QueryRow(`
		SELECT id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, classification, status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at
		FROM reply_events
		WHERE message_id = ?`,
		messageID,
	)
	var item ReplyEvent
	if err := row.Scan(&item.ID, &item.EnrollmentID, &item.MailboxID, &item.ThreadID, &item.MessageID, &item.ContactEmail, &item.Classification, &item.Status, &item.AssignedTo, &item.Subject, &item.Snippet, &item.DraftReply, &item.HandledAt, &item.OccurredAt); err != nil {
		if err == sql.ErrNoRows {
			return nil, fmt.Errorf("reply event %s not found", messageID)
		}
		return nil, err
	}
	item.NeedsAction = item.Status == "open"
	return &item, nil
}

func normalizeSuppressionScope(scope string) string {
	scope = strings.ToLower(strings.TrimSpace(scope))
	switch scope {
	case "domain":
		return "domain"
	default:
		return "email"
	}
}

func normalizeSuppressionValue(scope, value string) string {
	value = strings.ToLower(strings.TrimSpace(value))
	if scope == "domain" {
		value = strings.TrimPrefix(value, "@")
	}
	return value
}

func domainFromEmail(email string) string {
	parts := strings.SplitN(strings.ToLower(strings.TrimSpace(email)), "@", 2)
	if len(parts) != 2 {
		return ""
	}
	return parts[1]
}

func normalizeReplyClassification(classification string) string {
	switch strings.ToLower(strings.TrimSpace(classification)) {
	case "interested", "positive":
		return "interested"
	case "bounce", "bounced", "hard_bounce", "hard-bounce":
		return "bounced"
	case "unsubscribe", "opt_out", "opt-out":
		return "unsubscribe"
	case "not_interested", "negative":
		return "not_interested"
	case "out_of_office", "ooo", "away":
		return "out_of_office"
	case "referral":
		return "referral"
	default:
		return "replied"
	}
}

func replyStatus(classification string) string {
	switch classification {
	case "bounced", "unsubscribe", "not_interested":
		return "closed"
	default:
		return "open"
	}
}

func failedStatus(lastError string) string {
	if strings.TrimSpace(lastError) == "" {
		return ""
	}
	return TaskSendStatusFailed
}

func isNotFound(err error) bool {
	if err == nil {
		return false
	}
	return strings.Contains(strings.ToLower(err.Error()), "not found")
}

func newID(prefix string) string {
	return prefix + "_" + uuid.NewString()
}

func dayKey(now time.Time) string {
	return now.In(time.Local).Format("2006-01-02")
}

func daysUntil(value string, now time.Time) int {
	dueAt, err := time.Parse(time.RFC3339, value)
	if err != nil {
		return 0
	}
	return int(dueAt.Sub(now.UTC()).Hours() / 24)
}

func remaining(cap, used int) int {
	if cap <= 0 {
		return -1
	}
	return max(cap-used, 0)
}

func chooseString(candidate, fallback string) string {
	if candidate != "" {
		return candidate
	}
	return fallback
}

